3847.@use.source:
trigger use {
  int power = getObjVar( this, "power"); int cure_power_score = ( power * 0x4B); if( ! start_drink( user)) { return( 0x00); } setInvisible( user, 0x00); if( ( hasScript( user, "poisoned")) || ( hasObjVar( user, "poison_strength"))) { int poison = getObjVar( user, "poison_strength"); int poison_penalty_score = ( poison * 0x06D6); if( ( ( 0x2710 + ( cure_power_score - poison_penalty_score)) / 0x64) > random( 0x01, 0x64)) { doMobAnimation( user, 0x373A, 0x0A, 0x0F, 0x00, 0x00); sfx( getLocation( user), 0x01E0, 0x00); cure_poison( user); systemMessage( user, "You feel cured of poison!"); } else { systemMessage( user, "That potion was not strong enough to cure your ailment!"); } } obj empty_bottle = createGlobalObjectOn( this, 0x0F0E); destroyOne( this); return( 0x00);
}

3850.@use.source:
trigger use {
  if( ! start_drink( user)) { return( 0x00); } if( can_drink_potion( user) == 0x00) { return( 0x00); } setInvisible( user, 0x00); int power = 0x01; if( hasObjVar( this, "power")) { power = getObjVar( this, "power"); } if( ( hasScript( user, "poisoned")) || ( hasObjVar( user, "poison_strength"))) { systemMessage( user, "You are already poisoned."); } else { setObjVar( user, "poison_strength", power); attachScript( user, "poisoned"); } obj empty_bottle = createGlobalObjectOn( this, 0x0F0E); destroyOne( this); return( 0x00);
}

3851.@use.source:
trigger use {
  if( ! start_drink( user)) { return( 0x00); } setInvisible( user, 0x00); int cur_fatigue = getCurFatigue( user); int max_fatigue = getMaxFatigue( user); int restore_amt = 0xFA; if( hasObjVar( this, "power")) { restore_amt = getObjVar( this, "power"); } restore_amt = ( max_fatigue - cur_fatigue) * restore_amt / 0x03E8; if( ( cur_fatigue + restore_amt) < max_fatigue) { addFatigue( user, restore_amt); } else { setCurFatigue( user, max_fatigue); } obj empty_bottle = createGlobalObjectOn( this, 0x0F0E); deleteObject( this); return( 0x00);
}

3852.@use.source:
trigger use {
  if( hasObjVar( user, "potionHealed")) { barkToHued( user, user, 0x22, "You must wait 10 seconds before using another healing potion."); return( 0x00); } if( ! start_drink( user)) { return( 0x00); } if( can_drink_potion( user) == 0x00) { return( 0x00); } setInvisible( user, 0x00); int power = 0x64; if( hasObjVar( this, "power")) { power = getObjVar( this, "power"); } int heal_amount = random( power / 0x1E, power / 0x0A); addHP( user, heal_amount); systemMessage( user, "" + heal_amount + " points of damage have been healed."); obj empty_bottle = createGlobalObjectAt( 0x0F0E, getLocation( this)); setObjVar( user, "potionHealed", 0x01); attachScript( user, "potiontime"); callback( user, 0x0A, 0x57); deleteObject( this); return( 0x00);
}

