begging.@targetobj.source:
trigger targetobj {
  if( usedon == NULL( )) { return( 0x00); } if( ! isNPC( usedon)) { if( isPlayer( usedon)) { barkTo( usedon, user, "Perhaps just asking would work better."); } else { barkTo( usedon, user, "There is little chance of getting money from that!"); } return( 0x00); } if( ! isHuman( usedon)) { barkTo( usedon, user, "There is little chance of getting money from that!"); return( 0x00); } loc user_loc = getLocation( user); loc there = getLocation( usedon); if( getDistanceInTiles( user_loc, there) > 0x04) { int npc_type = getObjType( usedon); if( npc_type == 0x0190) { systemMessage( this, "You are too far away to beg from him."); } if( npc_type == 0x0191) { systemMessage( this, "You are too far away to beg from her."); } if( ( npc_type != 0x0190) && ( npc_type != 0x0190)) { systemMessage( this, "That's too far away.  You couldn't beg from it anyway."); } return( 0x00); } if( ! skillTest( user, 0x06)) { barkTo( usedon, user, "They seem unwilling to give you any money."); return( 0x00); } handleWatchingSkill( user, 0x06); setObjVar( usedon, "beggingVictim", usedon); setObjVar( usedon, "beggingBeggar", user); attachScript( usedon, "beggingpathfind"); bark( usedon, "I feel sorry for thee..."); walkTo( usedon, getLocation( user), 0x12); return( 0x00);
}

beggingpathfind.resolve_begging.source:
function void resolve_begging(obj beggar, obj victim) {
  removeObjVar( this, "beggingVictim"); removeObjVar( this, "beggingBeggar"); int amt = getMoney( victim) / 0x0A; if( amt > 0x0A) { amt = 0x0A; } if( ! getCompileFlag( 0x01)) { amt = amt + ( getNotoriety( beggar) / 0x0A); } else { int mod = amt + getAdjKarma( beggar) / 0x07D0; amt = amt + mod; } if( amt < 0x01) { bark( victim, "Thou dost not look trustworthy... no gold for thee today!"); return( ); } if( amt > getMoney( victim)) { bark( victim, "I have not enough money to give thee any!"); return( ); } obj gold = transferGenericToContainer( this, victim, 0x0EED, amt); if( gold == NULL( )) { bark( victim, "I have not enough money to give thee any!"); return( ); } obj given = giveItem( beggar, gold); if( given == NULL( )) { bark( victim, "I have not enough money to give thee any!"); return( ); } string msg = "Here, have "); string amt_str = amt; concat( msg, amt_str); concat( msg, " gold coin"); if( amt > 0x01) { concat( msg, "s."); } else { concat( msg, "."); } toUpper( msg, 0x00, 0x01); bark( beggar, msg); if( given == NULL( )) { int bar = teleport( gold, getLocation( beggar)); } detachScript( this, "beggingpathfind"); return( );
}

