function int count_metal(obj container) {
  int total = 0x00; list metal; clearList( metal); collect_metals( metal, container); for( int num = numInList( metal); num > 0x00; num --) { int amount; int result = getResource( amount, metal [ 0x00 ], "metal", 0x03, 0x02); total = total + amount; removeItem( metal, 0x00); } return( total);
