blacksmith.transfer_metal_to_item.source:
function void transfer_metal_to_item(obj item, obj source, int amount) {
  int total; list metal; clearList( metal); collect_metals( metal, source); for( int num = numInList( metal); num > 0x00; num --) { int metal_qty; obj metal_obj = metal [ 0x00 ]; int result = getResource( metal_qty, metal_obj, "metal", 0x03, 0x02); if( amount >= metal_qty) { transferResources( item, metal_obj, metal_qty, "metal"); deleteObject( metal_obj); removeItem( metal, 0x00); amount = amount - metal_qty; } else { transferResources( item, metal_obj, amount, "metal"); result = getResource( metal_qty, metal_obj, "metal", 0x03, 0x02); if( metal_qty < 0x01) { deleteObject( metal_obj); } break; } } clearList( metal); return( );
}

