blacksmith.collect_recipes.source:
function int collect_recipes(int metal, int skill, int start_idx, int depth) {
  int idx = start_idx; while( idx < 0x3D) { int entry_depth = getArrayIntElem( 0x00, 0x03, idx); if( entry_depth > depth) { int prev_count = numInList( recipe_indices); int next_idx = collect_recipes( metal, skill, idx + 0x01, depth + 0x01); int added_count = numInList( recipe_indices) - prev_count; if( added_count > 0x01) { truncateList( recipe_indices, prev_count); append( recipe_indices, idx); } idx = next_idx; } else { if( ( entry_depth < depth) || ( getArrayIntElem( 0x00, 0x01, idx) == 0x36)) { break; } if( can_craft( idx, metal, skill)) { append( recipe_indices, idx); } idx ++; } } return( idx);
}

blacksmith.register_item_recipes.source:
function int register_item_recipes(int row, int category, list types) {
  int debug = hasObjVar( this, "debugSkillInfo"); while( numInList( types)) { setArrayIntElem( 0x00, 0x00, row, types [ 0x00 ]); setArrayIntElem( 0x00, 0x03, row, category); obj temp_obj = createNoResObjectAt( types [ 0x00 ], getLocation( this)); int metal_cost = 0x00; int result = getResource( metal_cost, temp_obj, "metal", 0x03, 0x00); setArrayIntElem( 0x00, 0x04, row, metal_cost); int val; if( isReallyWeapon( temp_obj)) { val = metal_cost + ( getWeaponSpeed( temp_obj) * getAverageDamage( temp_obj) / 0x0C); } else { val = metal_cost + ( getMaxArmorClass( temp_obj) * 0x02); } setArrayIntElem( 0x00, 0x05, row, val); string description = getNameByType( types [ 0x00 ]); toUpper( description, 0x00, 0x01); if( debug) { description = description + ". $" + val + ", " + metal_cost + " metal"; } else { description = "Build " + description + ", " + metal_cost + " metal."; } setArrayStrElem( 0x00, 0x02, row, description); deleteObject( temp_obj); removeItem( types, 0x00); row ++; } return( row);
}

