  if( ! hasObjListVar( killer, "killcount")) { detachScript( this, "bounty"); return( ); } list kill_list; getObjListVar( kill_list, killer, "killcount"); obj bboard = findClosestBBoard( getLocation( this)); obj parchment; parchment = find_post_for_killer( bboard, killer); if( parchment == NULL( )) { parchment = createNoResObjectIn( 0x0EB0, bboard); } setObjVar( parchment, "killer", killer); obj bank = getItemAtSlot( killer, 0x1D); obj gold = doTakeMoney( bank, 0x0EED, 0xC350); if( gold == NULL( )) { if( 0x00) { bark( killer, "NULL reward!"); } } string reward = "alas, zero"; if( gold != NULL( )) { int tp_result = teleport( gold, getLocation( killer)); int gold_amount; int blah = getResource( gold_amount, gold, "gold", 0x03, 0x02); if( 0x00) { reward = gold_amount; systemMessage( killer, "Gold resource from bank:"); systemMessage( killer, reward); } transferResources( parchment, gold, gold_amount, "gold"); if( 0x00) { blah = getResource( gold_amount, gold, "gold", 0x03, 0x02); reward = gold_amount; systemMessage( killer, "Gold resource on gold after transfer:"); systemMessage( killer, reward); } blah = getResource( gold_amount, parchment, "gold", 0x03, 0x02); if( 0x00) { reward = gold_amount; systemMessage( killer, "Gold resource from board:"); systemMessage( killer, reward); } reward = gold_amount; if( 0x00) { bark( killer, "reward!"); bark( killer, reward); } deleteObject( gold); } string title_prefix; string title_suffix; string victim_name_a; string victim_name_b; switch( random( 0x00, 0x05)) { case 0x00 default title_prefix = "Bounty for "; title_suffix = "!"; break; case 0x01 title_prefix = ""; title_suffix = " must die!"; break; case 0x02 title_prefix = "A price on "; title_suffix = "!"; break; case 0x03 title_prefix = ""; title_suffix = " outlawed!"; break; case 0x04 title_prefix = "Execute "; title_suffix = "!"; break; case 0x05 title_prefix = "WANTED: "; title_suffix = "!"; break; } victim_name_a = kill_list [ random( 0x00, numInList( kill_list) - 0x01) ]; victim_name_b = kill_list [ random( 0x00, numInList( kill_list) - 0x01) ]; int kill_count = get_kill_count( killer); string dead = kill_count; list postText = title_prefix + getName( killer) + title_suffix, "  The foul scum known as", getName( killer), rand_accusation( killer), "For " + getHeShe( killer) + " is guilty of " + dead, "murders, among them those", "of " + victim_name_a + " and ", victim_name_b + ".", rand_preamble( killer), "of " + reward + " gold pieces", "for " + getHisHer( killer) + " head!", "  A description:", "    - " + get_hair_color( killer) + " hair", "    - " + get_hair_style( killer), "    - " + get_skin_tone( killer) + " skin", "  If you kill " + getHimHer( killer) + ", bring the", "head to a guard here in this", "city to claim your reward."; setObjVar( parchment, "postText", postText); return( );
}

bounty.setBounty.source:
function void setBounty(obj killer) {
  string debug_msg; postKillerToBB( killer); attachScript( killer, "bountymark"); setNotoriety( killer, ( 0x00 - 0x7F)); barkTo( killer, killer, "A bounty hath been issued for thee, and thy worldly goods are hereby confiscated!"); obj bank = getItemAtSlot( killer, 0x1D); list bank_contents; getContents( bank_contents, bank); for( int i = 0x00; i < numInList( bank_contents); i ++) { bank = bank_contents [ i ]; if( 0x00) { debug_msg = "Deleting bank item: " + getName( bank); systemMessage( killer, debug_msg); } deleteObject( bank); } return( );
}

bounty.apply_bounty_on_kill.source:
function void apply_bounty_on_kill(obj killer, obj victim) {
  if( process_kill_report( killer, victim) > 0x0A) { setBounty( killer); } return( );
}

bounty.@typeselected(0x01).source:
trigger typeselected(0x01) {
  if( listindex == 0x00) { systemMessage( this, "You have cancelled the bounty reporting process."); detachScript( this, "bounty"); return( 0x01); } switch( objtype) { case 0x00 if( ! hasObjVar( this, "myLastKiller")) { systemMessage( this, "An error has occurred and your murder cannot be reported."); detachScript( this, "bounty"); return( 0x01); } obj killer = getObjVar( this, "myLastKiller"); removeObjVar( this, "myLastKiller"); record_kill( killer, this); break; case 0x01 systemMessage( this, "You have cancelled the bounty reporting process."); break; default systemMessage( this, "You have cancelled the bounty reporting process."); break; } return( 0x01);
}

bounty.@callback(0x8C).source:
trigger callback(0x8C) {
  if( getMobFlag( this, 0x02)) { shortCallback( this, 0x01, 0x8C); return( 0x01); } obj killer = getObjVar( this, "bountyKiller"); prompt_report_murder( killer, this); return( 0x01);
}

bounty.@creation.source:
trigger creation {
  if( ! hasObjVar( this, "bountyKiller")) { if( 0x00) { bark( this, "Error attaching bounty script."); } detachScript( this, "bounty"); return( 0x01); } obj killer = getObjVar( this, "bountyKiller"); apply_bounty_on_kill( killer, this); return( 0x01);
}

bounty.@speech(\"add\").source:
trigger speech("add") {
  if( 0x00) { apply_bounty_on_kill( speaker, this); } return( 0x01);
}

bounty.@speech(\"count\").source:
trigger speech("count") {
  if( 0x00) { string kill_count_str; int bar = get_kill_count( this); kill_count_str = bar; bark( this, kill_count_str); } return( 0x01);
}

bountyboard.register_board.source:
function void register_board() {
  list args; multiMessageToLoc( getMasterObjLoc( 0x00), "registerBoard", args); return( );
}

bountyboard.get_hair_color.source:
function string get_hair_color(int hue) {
  if( ! hue) { return( ""); } hue = hue - 0x044C; switch( hue) { case 0x00 return( "indeterminate color"); break; case 0x01 case 0x02 case 0x03 return( "white"); break; case 0x04 case 0x05 case 0x06 return( "graying"); break; case 0x07 case 0x08 return( "black hair"); case 0x09 case 0x0A case 0x0B return( "copper"); break; case 0x0C case 0x0D case 0x0E case 0x0F return( "brown"); break; case 0x10 return( "reddish brown"); break; case 0x11 case 0x12 case 0x13 return( "blonde"); break; case 0x14 case 0x15 case 0x16 return( "light brown"); break; case 0x17 case 0x18 return( "golden brown"); break; case 0x19 case 0x1A case 0x1B return( "golden"); break; case 0x1C case 0x1D case 0x1E return( "bronze"); break; case 0x1F case 0x20 return( "dark brown"); break; case 0x21 case 0x22 return( "sandy"); break; case 0x23 case 0x24 case 0x25 return( "honey-colored"); break; case 0x26 case 0x27 case 0x28 return( "red"); break; case 0x29 case 0x2A case 0x2B return( "nut brown"); break; case 0x2C case 0x2D case 0x2E return( "rich brown"); break; case 0x2F case 0x30 return( "very dark brown"); break; } return( "outlandishly colored");
}

bountyboard.get_hair_style.source:
function string get_hair_style(int hair_type) {
  string style; switch( hair_type) { case 0x2049 style = "hair in two pigtails"; break; case 0x2047 style = "curly hair"; break; case 0x2046 style = "hair tied in buns"; break; case 0x204A style = "shaved head and topknot"; break; case 0x203C style = "hair worn long"; break; case 0x2044 style = "a mohawk hairstyle"; break; case 0x203D style = "hair tied back"; break; case 0x2045 style = "pageboy hair"; break; case 0x2048 style = "receding hairline"; break; case 0x203B style = "hair worn short"; break; default style = "bald"; break; } return( style);
}

bountyboard.get_skin_tone.source:
function string get_skin_tone(int hue) {
  string result; hue = hue - 0x03E8; hue = hue - 0x8000; switch( hue) { case 0x0F case 0x16 case 0x1D case 0x1E case 0x24 case 0x25 result = "pale"; break; case 0x08 case 0x09 case 0x17 case 0x1F case 0x2C case 0x2D case 0x01 case 0x02 case 0x10 case 0x11 case 0x12 case 0x2E result = "fair"; break; case 0x0A case 0x0B case 0x13 case 0x18 case 0x19 case 0x20 case 0x26 case 0x27 case 0x28 case 0x2F result = "tanned"; break; case 0x03 case 0x04 case 0x05 case 0x0C case 0x1A case 0x29 case 0x2A case 0x30 case 0x38 result = "copper"; break; case 0x06 case 0x07 case 0x0D case 0x0E case 0x14 case 0x15 case 0x1B case 0x1C case 0x21 case 0x22 case 0x23 case 0x2B case 0x31 case 0x32 case 0x39 result = "dark"; break; case 0x33 case 0x34 case 0x35 result = "yellow"; break; default result = "deathly"; break; } return( result);
}

bountyboard.get_killer_phrase.source:
function string get_killer_phrase(int murderCount) {
  list phrases = "hath murdered one too many!", "shall not slay again!", "hath slain too many!", "cannot continue to kill!", "must be stopped.", "is a bloodthirsty monster.", "is a killer of the worst sort.", "hath no conscience!", "hath cowardly slain many.", "must die for all our sakes.", "sheds innocent blood!", "must fall to preserve us.", "must be taken care of.", "is a thug and must die.", "cannot be redeemed.", "is a shameless butcher.", "is a callous monster.", "is a cruel, casual killer."; string result = phrases [ random( 0x00, numInList( phrases) - 0x01) ]; return( result);
}

bountyboard.get_bounty_intro.source:
function string get_bounty_intro(int bounty) {
  list phrases = "  A bounty is hereby offered", "  Lord British sets a price", "  Claim the reward! 'Tis", "  Lord Blackthorn set a price", "  The Paladins set a price", "  The Merchants set a price", "  Lord British's bounty "; string result = phrases [ random( 0x00, numInList( phrases) - 0x01) ]; return( result);
}

bountyboard.find_posting_for_killer.source:
function obj find_posting_for_killer(obj board, obj target_killer) {
  obj posting; obj killer; obj posted_killer; list contents; getContents( contents, board); int count = numInList( contents); for( int i = 0x00; i < count; i ++) { posting = contents [ i ]; if( getObjType( posting) == 0x0EB0) { if( hasObjVar( posting, "killer")) { killer = getObjVar( posting, "killer"); if( killer == target_killer) { return( posting); } } } } return( NULL( ));
}

bountyboard.postKillerToBB.source:
function void postKillerToBB(list args) {
  debugMessage( "postKillerToBB:  args="); printList( args); obj killer = args [ 0x00 ]; int bounty = args [ 0x01 ]; string killer_name = args [ 0x02 ]; list postText = killer_name + ":  " + bounty + "gold.                      "; if( numInList( args) > 0x03) { int murderCount = oprlist( args [ 0x03 ], 0x00); int is_female = oprlist( args [ 0x03 ], 0x01); int hair_type = oprlist( args [ 0x03 ], 0x02); int hair_hue = oprlist( args [ 0x03 ], 0x03); int skin_hue = oprlist( args [ 0x03 ], 0x04); obj bounty_post = find_posting_for_killer( this, killer); if( bounty_post == NULL( )) { bounty_post = createNoResObjectIn( 0x0EB0, this); } setObjVar( bounty_post, "killer", killer); string title_prefix; string title_suffix; string unused_a; string unused_b; switch( random( 0x00, 0x05)) { case 0x00 default title_prefix = "Bounty for "; title_suffix = "!"; break; case 0x01 title_prefix = ""; title_suffix = " must die!"; break; case 0x02 title_prefix = "A price on "; title_suffix = "!"; break; case 0x03 title_prefix = ""; title_suffix = " outlawed!"; break; case 0x04 title_prefix = "Execute "; title_suffix = "!"; break; case 0x05 title_prefix = "WANTED: "; title_suffix = "!"; break; } string obj_pronoun; string poss_pronoun; string subj_pronoun; if( is_female) { obj_pronoun = "her"; poss_pronoun = "her"; subj_pronoun = "she"; } else { obj_pronoun = "him"; poss_pronoun = "his"; subj_pronoun = "he"; } int wrap_count = wordWrap( postText, "The foul scum known as " + killer_name + " " + get_killer_phrase( murderCount) + "  For " + subj_pronoun + " is responsible for " + murderCount + " murders.  " + get_bounty_intro( bounty) + " of " + bounty + " gold pieces for " + poss_pronoun + " head!", 0x1C); appendToList( postText, "  A description:"); if( hair_hue) { appendToList( postText, "    - " + get_hair_color( hair_hue) + " hair"); } appendToList( postText, "    - " + get_hair_style( hair_type)); appendToList( postText, "    - " + get_skin_tone( skin_hue) + " skin"); appendToList( postText, "If you kill " + obj_pronoun + ", remove the"); appendToList( postText, "head, and give it to a guard"); appendToList( postText, "to claim your reward."); } else { appendToList( postText, "No information available."); } setObjVar( bounty_post, "postText", postText); setPostTime( bounty_post); return( );
}

bountyboard.@objectloaded.source:
trigger objectloaded {
  callback( this, 0x01, 0x2F); list contents; getContents( contents, this); for( int i = numInList( contents); i; i --) { deleteObject( contents [ 0x00 ]); removeItem( contents, 0x00); } return( 0x00);
}

bountyboard.@lookedat.source:
trigger lookedat {
  list contents; getContents( contents, this); int count = 0x00; for( int i = numInList( contents); i; i --) { if( hasObjVar( contents [ 0x00 ], "killer")) { count ++; } removeItem( contents, 0x00); } barkTo( this, looker, "a bounty board with " + count + " posted bounties"); return( 0x00);
}

bountyboard.@message(\"clearBounties\").source:
trigger message("clearBounties") {
  list contents; getContents( contents, this); for( int i = numInList( contents); i; i --) { deleteObject( contents [ 0x00 ]); removeItem( contents, 0x00); } return( 0x01);
}

bountyclaim.find_bounty_posting.source:
function obj find_bounty_posting(obj guard, obj killer) {
  obj posting; obj posted_killer; obj board = findClosestBBoard( getLocation( guard)); list contents; int found = 0x00; int blah; string gold_str; int gold; getContents( contents, board); int count = numInList( contents); for( int i = 0x00; i < count; i ++) { posting = contents [ i ]; if( getObjType( posting) == 0x0EB0) { if( 0x00) { blah = getResource( gold, posting, "gold", 0x03, 0x02); gold_str = gold; bark( guard, "Message has " + gold_str + " gold reward."); } if( hasObjVar( posting, "killer")) { posted_killer = getObjVar( posting, "killer"); if( killer == posted_killer) { if( 0x00) { bark( guard, "Posting for " + getName( killer) + " found!"); blah = getResource( gold, posting, "gold", 0x03, 0x02); gold_str = gold; bark( guard, "Message has " + gold_str + " gold reward."); } return( posting); } } } } return( NULL( ));
}

bountyclaim.@give.source:
trigger give {
  if( getObjType( givenobj) != 0x1DA0) { return( 0x01); } if( ! hasObjVar( givenobj, "bountyObjID")) { bark( this, "'Tis a decapitated head. How disgusting."); return( 0x00); } if( ! hasObjVar( givenobj, "bountyClaimant")) { bark( this, "'Tis a decapitated head. How disgusting."); return( 0x00); } obj killer = getObjVar( givenobj, "bountyObjID"); obj claimant = getObjVar( givenobj, "bountyClaimant"); obj claim = find_bounty_posting( this, killer); if( claim == NULL( )) { bark( this, "There is indeed a price on this head, but not here. Travel on, my friend, to a precinct of the guards that will pay thee."); return( 0x00); } if( getNotorietyLevel( giver) < 0x01) { bark( this, "We only accept bounty hunting from honorable folk! Away with thee!"); return( 0x00); } if( giver != claimant) { bark( this, "I had heard that this scum was taken care of. But thou didst not do the deed, and thus shall not get the reward!"); deleteObject( claim); return( 0x00); } deleteObject( givenobj); int gold_amount; string gold_str; int blah = getResource( gold_amount, claim, "gold", 0x03, 0x02); gold_str = gold_amount; obj reward = createNoResObjectAt( 0x0EED, getLocation( giver)); transferResources( reward, claim, gold_amount, "gold"); if( giveItem( giver, reward) == NULL( )) { int ok = teleport( reward, getLocation( giver)); } string msg = "The reward is " + gold_amount + " gold pieces. Here you go!"); bark( this, msg); deleteObject( claim); sfx( getLocation( giver), 0x35, 0x00); return( 0x00);
}

bountyinfo.schedule_periodic_callback.source:
function void schedule_periodic_callback() {
  callbackAdvanced( this, 0x004F1A00, 0x01, 0x00); return( );
}

bountyinfo.broadcast_bounty_update.source:
function void broadcast_bounty_update() {
  if( ! is_active) { return( ); } list args = subject, bounty, killer_name; if( numInList( descriptor_list) > 0x00) { appendToList( args, descriptor_list); } messageToRange( getMasterObjLoc( 0x00), 0x01, "updateBounty", args); return( );
}

bountyinfo.send_bounty_info.source:
function void send_bounty_info(obj recipient) {
  list args = subject, bounty, killer_name; bark( this, "messaging via probe to (" + objtoint( recipient) + ")."); relay_message( recipient, "bountyInfo", args); return( );
}

bountyinfo.teleported.source:
function void teleported() {
  list args = subject; messageToRange( getLocation( this), 0x01, "consolidateBounty", args); broadcast_bounty_update( ); callback( this, random( 0x0E10, 0x0FA0), 0x2F); return( );
}

bountyinfo.@lookedat.source:
trigger lookedat {
  if( ! isEditing( looker)) { return( 0x00); } string status_str = "(active)"; if( ! is_active) { status_str = "(inactive)"; } string descriptor = "???"; if( numInList( descriptor_list) > 0x00) { int desc_val = descriptor_list [ 0x00 ]; descriptor = desc_val; } barkTo( this, looker, "Bounty for " + killer_name + " (" + objtoint( subject) + ") with " + descriptor + " kills and " + bounty + " gold. " + status_str); return( 0x00);
}

bountyinfo.@creation.source:
trigger creation {
  subject = getObjVar( this, "subject"); removeObjVar( this, "subject"); return( 0x01);
}

bountyinfo.@destroyed.source:
trigger destroyed {
  if( subject == NULL( )) { return( 0x01); } broadcast_bounty_update( ); return( 0x01);
}

bountyinfo.@message(\"setBountyActivity\.source:
trigger message("setBountyActivity") {
  if( subject != oprlist( args, 0x00)) { return( 0x01); } is_active = oprlist( args, 0x01); schedule_periodic_callback( ); broadcast_bounty_update( ); return( 0x01);
}

bountyinfo.@message(\"addBounty\").source:
trigger message("addBounty") {
  debugMessage( "addBounty args="); printList( args); if( subject != oprlist( args, 0x00)) { return( 0x01); } bounty = bounty + oprlist( args, 0x01); if( args [ 0x02 ]) { is_active = 0x01; } if( killer_name == "") { killer_name = args [ 0x03 ]; } if( numInList( descriptor_list) == 0x00) { if( numInList( args) > 0x04) { copyList( descriptor_list, args [ 0x04 ]); } } schedule_periodic_callback( ); return( 0x00);
}

bountyinfo.@message(\"updateBountyDesc\".source:
trigger message("updateBountyDesc") {
  if( subject != oprlist( args, 0x00)) { return( 0x01); } removeItem( args, 0x00); descriptor_list = args; is_active = 0x01; broadcast_bounty_update( ); return( 0x01);
}

bountyinfo.@message(\"consolidateBounty\.source:
trigger message("consolidateBounty") {
  if( this == sender) { return( 0x01); } if( subject != oprlist( args, 0x00)) { return( 0x01); } args = subject, bounty, is_active, "", descriptor_list; message( sender, "addBounty", args); setDefaultReturn( 0x01); subject = NULL( ); deleteObjectNoFall( this); return( 0x01);
}

bountyinfo.@message(\"takeBounty\").source:
trigger message("takeBounty") {
  if( ! is_active) { return( 0x01); } if( subject != oprlist( args, 0x00)) { return( 0x01); } bark( this, "(" + objtoint( args [ 0x01 ]) + ") is collecting this bounty for " + killer_name); send_bounty_info( args [ 0x01 ]); setDefaultReturn( 0x01); bounty = 0x00; deleteObjectNoFall( this); return( 0x00);
}

bountyinfo.@callback(0x2F).source:
trigger callback(0x2F) {
  broadcast_bounty_update( ); callback( this, random( 0x0E10, 0x0FA0), 0x2F); return( 0x01);
}

bountykillcount.@creation.source:
trigger creation {
  if( ! hasObjVar( this, "killcount")) { bark( this, "No kills are tallied on this person."); detachScript( this, "bountykillcount"); } int x; list kill_list; getObjListVar( kill_list, this, "killcount"); x = numInList( kill_list); string blah = x; bark( this, "There are " + blah + " kills reported on this character."); if( hasScript( this, "bountymark")) { bark( this, "There is a bounty outstanding as well."); } detachScript( this, "bountykillcount"); return( 0x01);
}

bountymark.get_kill_count.source:
function int get_kill_count(obj killer) {
  if( ! hasObjListVar( killer, "killcount")) { return( 0x00); } list kills; getObjListVar( kills, killer, "killcount"); return( numInList( kills));
}

bountymark.penalize_skills_stats.source:
function void penalize_skills_stats(obj m_target) {
  if( 0x00) { bark( m_target, "Penalizing stats."); } for( int i = 0x00; i < 0x2E; i ++) { loseSkillLevel( m_target, i, ( getSkillLevel( m_target, i) / 0x0A)); } int result; for( i = 0x00; i < 0x03; i ++) { result = modifyRealStat( m_target, i, ( 0x00 - getRealStat( m_target, i) / 0x0A)); } removeObjVar( m_target, "killcount"); return( );
}

bountymark.@creation.source:
trigger creation {
  if( 0x00) { bark( this, "I am now bounty hunted!"); } return( 0x01);
}

bountymark.@time(\"hour:12\").source:
trigger time("hour:12") {
  if( ! hasObjListVar( this, "killcount")) { return( 0x01); } list kill_list; getObjListVar( kill_list, this, "killcount"); removeObjVar( this, "killcount"); removeItem( kill_list, 0x01); if( numInList( kill_list) > 0x00) { setObjVar( this, "killcount", kill_list); } if( 0x00) { bark( this, "Reducing bounty count."); } return( 0x01);
}

bountymark.@death.source:
trigger death {
  if( ! isPlayer( attacker)) { return( 0x01); } if( getNotorietyLevel( attacker) < 0x01) { if( 0x00) { bark( this, "Killer must be above neutral to collect bounty."); } return( 0x01); } if( get_kill_count( attacker) >= get_kill_count( this)) { if( 0x00) { bark( this, "You have a higher killcount than the victim and cannot claim the bounty."); } return( 0x01); } obj head; barkTo( attacker, attacker, "As you kill them, you realize there is a bounty on their head! You take the head as evidence of your victory."); head = createGlobalObjectIn( 0x1DA0, this); string head_name = "the head of " + getName( this); setObjVar( head, "lookAtText", head_name); if( giveItem( attacker, head) == NULL( )) { int r = teleport( head, getLocation( attacker)); } setObjVar( head, "bountyObjID", this); setObjVar( head, "bountyClaimant", attacker); penalize_skills_stats( this); shortCallback( this, 0x7F, 0x01); return( 0x01);
}

bountymasterboard.get_display_start.source:
function int get_display_start() {
  int count = numInList( bounty_list); int start = count - 0x14; if( start < 0x00) { start = 0x00; } return( start);
}

bountymasterboard.get_bounty_count.source:
function int get_bounty_count() {
  return( numInList( bounty_list));
}

bountymasterboard.update_boards.source:
function void update_boards(int start, int count) {
  if( hasCallback( this, 0x2F)) { return( ); } for( int board_idx = numInList( registered_board_list) - 0x01; board_idx >= 0x00; board_idx --) { list args; multiMessage( registered_board_list [ board_idx ], "clearBounties", args); for( int i = count - 0x01; i >= start; i --) { debugMessage( "updating board#" + board_idx + " with bounty#" + i + "."); multiMessage( registered_board_list [ board_idx ], "setBounty", bounty_list [ i ]); } } return( );
}

bountymasterboard.addBounty.source:
function int addBounty(list args) {
  int bounty = args [ 0x01 ]; int count = numInList( bounty_list); for( int i = 0x00; i < count; i ++) { int cur_bounty = oprlist( bounty_list [ i ], 0x01); if( bounty <= cur_bounty) { break; } } if( count >= 0x32) { if( i <= 0x00) { return( 0x00 - 0x01); } i --; removeItem( bounty_list, 0x00); } insertInList( bounty_list, args, i); return( i);
}

bountymasterboard.@objectloaded.source:
trigger objectloaded {
  clearList( bounty_list); clearList( registered_board_list); callback( this, 0x0A, 0x2F); return( 0x01);
}

bountymasterboard.@lookedat.source:
trigger lookedat {
  int start = get_display_start( ); int count = get_bounty_count( ); int max_bounty = 0x00; int min_bounty = 0x00; if( count > 0x00) { max_bounty = oprlist( bounty_list [ count - 0x01 ], 0x01); min_bounty = oprlist( bounty_list [ start ], 0x01); } barkTo( this, looker, "" + count + " bounties starting at #" + start + " and ranging from " + min_bounty + " to " + max_bounty + " are posted on " + numInList( registered_board_list) + " bounty boards."); return( 0x00);
}

