  obj subject = args [ 0x00 ]; int bounty = args [ 0x01 ]; int count = numInList( bounty_list); string name = args [ 0x02 ]; debugMessage( "Bounty updating:  " + bounty + " gold for " + name + "."); for( int i = 0x00; i < count; i ++) { obj entry_obj = oprlist( bounty_list [ i ], 0x00); if( entry_obj == subject) { break; } } int new_idx; int start; if( i == count) { if( bounty == 0x00) { return( 0x01); } new_idx = addBounty( args); start = get_display_start( ); if( new_idx < start) { return( 0x01); } update_boards( start, get_bounty_count( )); } else { int old_bounty = oprlist( bounty_list [ i ], 0x01); debugMessage( "updating existing bounty from " + old_bounty + " to " + bounty + "."); if( old_bounty == bounty) { return( 0x01); } removeItem( bounty_list, i); if( bounty > 0x00) { new_idx = addBounty( args); if( i < new_idx) { i = new_idx; } } start = get_display_start( ); if( i < start) { return( 0x01); } update_boards( start, get_bounty_count( )); } return( 0x01);
