function void apply_water_embankment(loc place) {
  int upper_left_tile; int upper_tile; int upper_right_tile; int left; int right; int lower_left_tile; int lower; int lower_right_tile; int current_tile = getTile( place); int x = getX( place); int y = getY( place); loc sample_loc = place; int c = 0x00; loc elev_source_loc = place; int transition_index = getTile( place); setX( sample_loc, x - 0x01); left = getTile( sample_loc); setY( sample_loc, y - 0x01); upper_left_tile = getTile( sample_loc); setX( sample_loc, x); upper_tile = getTile( sample_loc); setX( sample_loc, x + 0x01); upper_right_tile = getTile( sample_loc); setY( sample_loc, y); right = getTile( sample_loc); setY( sample_loc, y + 0x01); lower_right_tile = getTile( sample_loc); setX( sample_loc, x); lower = getTile( sample_loc); setX( sample_loc, x - 0x01); lower_left_tile = getTile( sample_loc); if( is_target_tile( current_tile)) { return( ); } if( ( is_target_tile( upper_left_tile)) && ( ! is_target_tile( left)) && ( ! is_target_tile( upper_tile))) { transition_index = 0x0D; c = 0x01; elev_source_loc = getX( place) - 0x01, getY( place) - 0x01, getZ( place); } if( ( is_target_tile( upper_right_tile)) && ( ! is_target_tile( right)) && ( ! is_target_tile( upper_tile))) { transition_index = 0x0E; c = 0x01; elev_source_loc = getX( place) - 0x01, getY( place) + 0x01, getZ( place); } if( ( is_target_tile( lower_right_tile)) && ( ! is_target_tile( right)) && ( ! is_target_tile( lower))) { transition_index = 0x0F; c = 0x01; } if( ( is_target_tile( lower_left_tile)) && ( ! is_target_tile( left)) && ( ! is_target_tile( lower))) { transition_index = 0x10; c = 0x01; } if( ( is_target_tile( left)) && ( ! is_target_tile( right))) { transition_index = random( 0x01, 0x03); c = 0x01; elev_source_loc = getX( place) - 0x01, getY( place), getZ( place); } if( ( is_target_tile( right)) && ( ! is_target_tile( left))) { transition_index = random( 0x07, 0x09); c = 0x01; } if( ( is_target_tile( upper_tile)) && ( ! is_target_tile( lower))) { transition_index = random( 0x04, 0x06); c = 0x01; elev_source_loc = getX( place), getY( place) - 0x01, getZ( place); } if( ( is_target_tile( lower)) && ( ! is_target_tile( upper_tile))) { transition_index = random( 0x0A, 0x0C); c = 0x01; } if( ( is_target_tile( left)) && ( is_target_tile( upper_tile))) { transition_index = 0x0D + 0x06; c = 0x01; } if( ( is_target_tile( left)) && ( is_target_tile( lower))) { transition_index = 0x0C + 0x06; c = 0x01; elev_source_loc = getX( place) - 0x01, getY( place) + 0x01, getZ( place); } if( ( is_target_tile( right)) && ( is_target_tile( upper_tile))) { transition_index = 0x0E + 0x06; c = 0x01; elev_source_loc = getX( place) - 0x01, getY( place) - 0x01, getZ( place); } if( ( is_target_tile( right)) && ( is_target_tile( lower))) { transition_index = 0x0B + 0x06; c = 0x01; } if( c) { setTile( place, transition_table [ transition_index ]); } setElevation( place, getElevation( elev_source_loc)); return( );
