 if( ammo_obj == NULL( )) { if( ammo_type == 0x0F42) { ebarkTo( user, user, "You do not have any arrows with which to practice."); } else { ebarkTo( user, user, "You do not have any crossbow bolts with which to practice."); } return( 0x01); } string ammo_name; int user_x = getX( user_loc); int user_y = getY( user_loc); int butte_x = getX( there); int butte_y = getY( there); if( butte_type == 0x100A) { if( user_x < butte_x) { ebarkTo( user, user, "You would do better to stand in front of the archery butte."); return( 0x01); } if( user_y != butte_y) { ebarkTo( user, user, "You aren't properly lined up with the archery butte to get an accurate shot."); return( 0x01); } if( ( user_x - butte_x) > 0x06) { ebarkTo( user, user, "You are too far away from the archery butte to get an accurate shot."); return( 0x01); } if( ( user_x - butte_x) < 0x05) { ebarkTo( user, user, "You are too close to the target."); return( 0x01); } } if( butte_type == 0x100B) { if( user_y < butte_y) { ebarkTo( user, user, "You would do better to stand in front of the archery butte."); return( 0x01); } if( user_x != butte_x) { ebarkTo( user, user, "You aren't properly lined up with the archery butte to get an accurate shot."); return( 0x01); } if( ( user_y - butte_y) > 0x06) { ebarkTo( user, user, "You are too far away from the archery butte to get an accurate shot."); return( 0x01); } if( ( user_y - butte_y) < 0x05) { ebarkTo( user, user, "You are too close to the target."); return( 0x01); } } if( getItemAtSlot( user, 0x19) != NULL( )) { anim_frames = 0x05; anim_id = 0x1B; } else { anim_id = 0x12; } if( ! isHuman( user)) { anim_frames = 0x04; anim_id = random( 0x04, 0x06); } animateMobile( user, anim_id, anim_frames, 0x01, 0x00, 0x00); doMissile_Mob2Loc( user, there, ammo_type, 0x05, 0x00, 0x00); shooter = user; callback( this, 0x01, 0x19); if( getQuantity( ammo_obj) > 0x01) { ammo = createNoResObjectAt( getObjType( ammo_obj), getLocation( this)); transferGeneric( ammo, ammo_obj, 0x01); } else { res