  if( ! isInMap( place)) { if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } return( 0x00); } if( placement_ready) { placement_ready = 0x00; debugMessage( "before canExistAt"); if( canExistAt( place, getTileHeight( item_type), 0x00) != 0x07) { debugMessage( "inside canExistAt"); systemMessage( user, "You cannot create that there."); return( 0x00); } if( getDistanceInTiles( place, getLocation( user)) > 0x03) { systemMessage( user, "That is too far away."); return( 0x00); } int avail_wood = 0x00; int ret = getResource( avail_wood, wood_source, "wood", 0x03, 0x02); if( avail_wood < ( wood_cost + 0x01)) { systemMessage( user, "You don't have enough wood to make that."); return( 0x00); } obj item = createNoResObjectAt( item_type, place); transferResources( item, wood_source, wood_cost, "wood"); setObjVar( item, "chopable", 0x01); switch( item_type) { case 0x0E7D case 0x0E7E overloadWeight( item, 0x01); break; case 0x0B5E case 0x0A2A case 0x0B5A case 0x0B56 case 0x0B4E case 0x0B52 case 0x0B2F case 0x0B33 overloadWeight( item, 0x01); break; case 0x0B2C case 0x0B34 case 0x0B4A case 0x0B7C case 0x0B7D overloadWeight( item, 0x01); break; case 0x0E3E case 0x0E3C case 0x0E42 case 0x0A9E case 0x0A51 case 0x0A53 overloadWeight( item, 0x01); break; default break; } switch( item_type) { case 0x0E7D case 0x0E42 if( testSkill( user, 0x25)) { int tinker_skill = getSkillLevel( user, 0x25); systemMessage( user, "Your tinker skill was sufficient to make the item lockable."); attachScript( item, "locked"); setObjVar( item, "lockLevel", ( tinker_skill * 0x02)); setObjVar( item, "playerMade", 0x01); obj key = createNoResObjectIn( 0x100E, item); list unlock_list = item; setObjVar( key, "whatIUnlock", unlock_list); } } obj kindling = createNoResObjectAt( 0x0DE1, place); transferResources( kindling, wood_source, 0x01, "wood"); int remaining_wood; ret = getResource( remaining_wood, wood_source, "wood", 0x03, 0x02); if( remaining_wood < 0x01) { deleteObject( wood_source); } } if( hasObjVar( wood_source, "inUse")) { removeObjVar( wood_source, "inUse") } if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } if( drain_tool_life( user, this)) { deleteObject( this); } return( 0x00);
