function void warn_target(obj this, obj target) {
  string msg; list messages; string bark_str; int dir; string notoriety_str; int rep; if( ! getCompileFlag( 0x01)) { rep = getNotoriety( target); } else { rep = getKarma( target); } notoriety_str = rep; int rep_level; if( ! getCompileFlag( 0x01)) { rep_level = ( 0x00 - ( getNotoriety( target) / 0x0A)); } else { rep_level = getKarmaLevel( target); } messages = "Don't do anything foolish.", "We'll be keeping an eye on thee.", "I know thy type. Break not the laws, or else suffer punishment!", "Thou hast a suspicious look about thee.", "I trust thee not, nor should anyone. Thou art a ruffian.", "Faugh, another scoundrel to keep an eye on!", "I have heard of thee--keep thee to the straight and narrow whilst here!", "If I catch thee breaking laws, thy neck will be on the line.", "Thou hast an unsavory reputation--best that thou dost not prove that thou earnst it.", "Thou art known as a criminal. Do not draw the attention of the guards with thy deeds, or risk death!", "Mine eye is on thee, scoundrel. Break not the law.", "Thou art a scofflaw, but while here thou SHALT obey the laws, or suffer.", "Look thee who crawled out from under a rock! Well, thou shalt not do anything illegal whilst I am watching thee!", "The guards well know thee and thy nefarious ways! Be sure to behave thyself!", "Scum! Stay not overlong here, for thou art not welcome!", "I hope that thou art merely visiting, for we mislike knaves mingling with our citizens.", "Thou shouldst leave this city before any decide to lynch thee.", "I should arrest thee now, before thou dost something terrible. Thou art well known as a rogue of the worst kind."; int msg_index = random( 0x00, 0x0C) + ( rep_level / 0x02); msg = messages [ msg_index ]; bark_str = getName( target) + "! " + msg; dir = getDirectionInternal( getLocation( this), getLocation( target)); faceHere( this, dir); bark( this, bark_str); setObjVar( target, "cityguardJustWarnedMe", 0x01); return( );
}

