) && ( hour < 0x15)) { hour_str = hour_str + " in the afternoon"; } if( hour > 0x14) { hour_str = hour_str + " at night"; } msg = "It is " + minute_str + " " + hour_str + "."; ebarkTo( this, user, msg); return( 0x01);
