duperfind.has_illegal_stats.source:
function int has_illegal_stats(obj mobile) {
  int s = getRealStrength( mobile); int d = getRealDexterity( mobile); int i = getRealIntelligence( mobile); int stat_sum = abs( s) + abs( d) + abs( i); int str_mod = abs( getStatMod( mobile, 0x00)); int dex_mod = abs( getStatMod( mobile, 0x01)); int int_mod = abs( getStatMod( mobile, 0x02)); int stat_mod_sum = str_mod + dex_mod + int_mod; if( ( s < 0x00) || ( d < 0x00) || ( i < 0x00) || ( s > 0x69) || ( d > 0x69) || ( i > 0x69) || ( stat_sum > 0xEB)) { return( 0x01); } if( ( str_mod > 0x0F) || ( dex_mod > 0x0F) || ( int_mod > 0x0F) || ( stat_mod_sum > 0x28)) { return( 0x01); } int skill_total = 0x00; int skill_mod_total = 0x00; for( int skill_idx = 0x00; skill_idx < 0x2E; skill_idx ++) { int skill_level = getSkillLevelNoStatNoMod( mobile, skill_idx); int abs_skill = abs( skill_level); int skill_mod = getSkillMod( mobile, skill_idx); int abs_mod = abs( skill_mod); if( ( skill_level < 0x00) || ( skill_level > 0x041A) || ( abs_mod > 0x012C)) { return( 0x01); } skill_total = skill_total + abs_skill; skill_mod_total = skill_mod_total + abs_mod; } if( ( skill_total > 0x1BBC) || ( skill_mod_total > 0x01F4)) { return( 0x01); } return( 0x00);
}

