escort.set_ad_text.source:
function void set_ad_text(int quest_type) {
  switch( quest_type) { default case 0x00 dialogue_lines = "  Greetings!", "  I am a poor healer who", "seeks a worthy escort. I", "can offer some small pay", "to any doughty warrior", "able to assist me. It is", "imperative that I reach my", "destination, or innocents", "may perish!"; break; case 0x01 dialogue_lines = "  'Tis a terrible thing", "to be a parent with an", "ungrateful child! Yet such", "is my situation.", "  Because of the poor", "behavior and lack of", "character of this offspring", "of mine, I am obliged to", "foster them away from", "home.", "  So now I am in need of", "an able escort of good", "character who might serve", "as role model, and who can", "ensure that my child", "reaches their destination", "safely.", "  I shall let my child", "post their whereabouts so", "that thou mayst meet with", "them and arrange terms.           ---"; break; case 0x02 dialogue_lines = "  I am so happy! I am to", "be married, and my life", "will finally be complete!", "  Alas, I am no warrior,", "and the wedding is not to", "take place here. I am in", "need of an escort, for the", "roads are treacherous and", "my future spouse would be", "sad indeed to hear that", "an ettin ate me before the", "wedding."; break; case 0x03 dialogue_lines = "  Wizard seeks escort to a", "conference."; break; case 0x04 dialogue_lines = "  Reputable merchant seeks", "able warriors to serve as", "mercantile escort. Pay is", "scale; we prefer to hire", "experienced mercenaries."; break; case 0x05 dialogue_lines = "  I am one of Lord British's", "couriers, and I seek an able", "warrior to escort me safely,", "as the message I carry is of", "utmost importance to the", "realm!"; break; case 0x06 dialogue_lines = "  'Tis a bit of a problem to", "admit it, but our normally", "trustworthy household guard", "seem to have broken his leg!", "  If thou art able with a", "weapon, we are pleased to take", "applications for his", "replacement, to serve as", "guard and escort on our", "forthcoming journey."; break; case 0x07 dialogue_lines = "  I've always wished for", "adventure! Now I can have it", "at last!", "  My weaponsmaster in school", "always said I was a dab hand", "with a blade, and I am afire", "with the love of adventure!", "  Plus I have money.", "  So if you are willing to", "hire on as my bodyguard and", "join me as we seek the deepest", "depths of the Abyss, and", "as we conquer dragons with", "the rapid flick of our sharp", "swords, disregarding all", "danger and ignorant of fear,", "seek me out!", "  Cowards need not apply!"; break; } return( );
}

escort.post_bulletin_board_notice.source:
function void post_bulletin_board_notice(obj this) {
  list scratch; obj board = findClosestBBoard( getLocation( this)); obj post = createNoResObjectIn( 0x0EB0, board); loc unused_loc; string unused_str; string title; list title_options = "Escort needed", "Guard needed", "I need an escort!", "Traveling companion?", "Seeking companion", "Now hiring", "Hiring a guard", "Hiring an escort", "Seeking escort"; title = title_options [ random( 0x00, numInList( title_options) - 0x01) ]; list postText = title; set_ad_text( escort_type); list location_lines = "  I can be found", getDistance( getLocation( board), getLocation( this)), getDirection( getLocation( board), getLocation( this)) + "", "of here. When thou dost find", "me, look at me close to accept", "the task of taking me to", get_city_name( dest_code) + ".", "    " + getName( this); string blah; for( int i = 0x00; i < numInList( dialogue_lines); i ++) { blah = dialogue_lines [ i ]; appendToList( postText, blah); } for( i = 0x00; i < numInList( location_lines); i ++) { blah = location_lines [ i ]; appendToList( postText, blah); } setObjVar( post, "postText", postText); setObjVar( this, "myBoardPost", post); return( );
}

