escort.@speech(\"I will take thee\").source:
trigger speech("I will take thee") {
  if( getDistanceInTiles( getLocation( speaker), getLocation( this)) > 0x03) { return( 0x01); } if( ! hasObjVar( this, "isWaitingForEscort")) { if( hasObjVar( this, "myEscort")) { bark( this, "I am already being led!"); } else { bark( this, "I am sorry, but I do not wish to go anywhere."); callback( this, 0x64, 0x7A); } return( 0x01); } if( isDead( speaker)) { return( 0x01); } if( hasObjVar( this, "myBoardPost")) { obj board_post = getObjVar( this, "myBoardPost"); deleteObject( board_post); } string msg = "Lead on! Payment will be made when we arrive in " + get_city_name( dest_code) + "."; bark( this, msg); removeObjVar( this, "isWaitingForEscort"); followNpc( this, speaker, 0x00); setObjVar( this, "myEscort", speaker); callback( this, 0x05, 0x01); return( 0x00);
}

escort.@callback(0x01).source:
trigger callback(0x01) {
  if( ! hasObjVar( this, "myEscort")) { enableBehaviors( this); callback( this, 0x64, 0x7A); return( 0x01); } obj escort = getObjVar( this, "myEscort"); if( ! isInArea( dest_code, getLocation( this), 0x00)) { poll_count = poll_count + 0x01; if( poll_count > 0x06) { poll_count = 0x00; if( getDistanceInTiles( getLocation( this), getLocation( escort)) > 0x1E) { bark( this, "My escort seems to have abandoned me!"); enableBehaviors( this); callback( this, 0x64, 0x7A); return( 0x01); } } callback( this, 0x05, 0x01); return( 0x01); } stopFollowing( this); removeObjVar( this, "myEscort"); string arrival_msg = "We have arrived! I thank thee, " + getName( escort) + "! I have no further need of thy services. Here is thy pay."; bark( this, arrival_msg); if( ! getCompileFlag( 0x01)) { if( getNotoriety( escort) < 0x7F) { addNotoriety( escort, 0x01); } } else { changeFame( escort, 0x03E8); } obj reward = requestCreateObjectAt( 0x0EED, getLocation( escort)); int success; if( reward != NULL( )) { success = requestAddQuantity( reward, random( 0x64, 0x01F4)); } if( ! success) { bark( this, "I fear that I lied about a reward, however. I lack any funds."); deleteObject( reward); enableBehaviors( this); callback( this, 0x64, 0x7A); return( 0x01); } obj backpack = getBackpack( escort); success = putObjContainer( reward, backpack); enableBehaviors( this); callback( this, 0xC8, 0x7A); return( 0x01);
}

