femalearmor.@callback(0x88).source:
trigger callback(0x88) {
  obj wearer = containedBy( this); int result; if( wearer != NULL( )) { if( isMobile( wearer)) { int slot = getEquipSlot( this); if( this == getItemAtSlot( wearer, slot)) { if( getObjType( wearer) == 0x0190) { barkTo( wearer, wearer, "Only females can wear this."); if( canHold( wearer, this)) { result = toMobile( this, wearer); } else { result = teleport( this, getLocation( wearer)); } } } } } return( 0x01);
}

