globals.teleport_followers.source:
function void teleport_followers(obj boss, loc destination) {
  list mobs; list boss_list; obj it; int should_teleport = 0x00; getMobsInRange( mobs, getLocation( boss), 0x19); for( int i = 0x00; i < numInList( mobs); i ++) { it = mobs [ i ]; should_teleport = 0x00; if( hasObjListVar( it, "myBoss")) { getObjListVar( boss_list, it, "myBoss"); if( isInList( boss_list, boss)) { if( getLeader( it) == boss) { should_teleport = 0x01; } } } else { if( isNPC( it)) { if( getLeader( it) == boss) { should_teleport = 0x01; } } } if( should_teleport) { if( check_britannia_boundary_allowed( it, getLocation( it), destination, "teleport there")) { int r = teleport( it, destination); } } } return( );
}

gm.@creation.source:
trigger creation {
  int guild_id; member string guildName; member int my_guild; loc my_loc = getLocation( this); setObjVar( this, "myGuildLocation", my_loc); setLoiterMode( this, 0x01); goLoiter( this, my_loc, 0x03E8); callBack( this, 0x64, 0x60); setBehavior( this, 0x02); if( hasObjVar( this, "guildMember")) { guild_id = getObjVar( this, "guildMember"); } if( ! guild_id) { setObjVar( this, "guildMember", 0x00); } my_guild = guild_id; switch( guild_id) { case 0x00 guildName = "Default Guild of Superheroic Non-Player Characters"; break; case 0x01 guildName = "Guild of Arcane Arts"; break; case 0x02 guildName = "Warrior's Guild"; break; case 0x03 guildName = "Society of Thieves"; break; case 0x04 guildName = "League of Rangers"; break; case 0x05 guildName = "Guild of Healers"; break; case 0x06 guildName = "Mining Cooperative"; break; case 0x07 guildName = "Merchants' Association"; break; case 0x08 guildName = "Order of Engineers"; break; case 0x09 guildName = "Society of Clothiers"; break; case 0x0A guildName = "Maritime Guild"; break; case 0x0B guildName = "Bardic Collegium"; break; default guildName = "Default Guild of Superheroic Non-Player Characters"; break; } return( 0x00);
}

gm.@callback(0x60).source:
