  if( hasObjVar( this, "myGuildLocation")) { loc there = getObjVar( this, "myGuildLocation"); if( getDistanceInTiles( getLocation( this), there) > 0x0A) { int result = teleport( this, there); } } callBack( this, 0x64, 0x60); return( 0x01);
}

gm.@pathnotfound(0x06).source:
