}

gm.@speech(\"*\").source:
trigger speech("*") {
  string word; list args; int guild_id; string phrases; if( ! check_convo_eligibility( this, speaker, arg)) { return( 0x01); } split( args, arg); for( int i = 0x00; i < numInList( args); i ++) { word = args [ i ]; if( word == "join" || ( word == "member")) { if( hasObjVar( speaker, "guildMember")) { guild_id = getObjVar( speaker, "guildMember"); if( guild_id != my_guild) { bark( this, "Thou must resign from thy other guild first."); return( 0x00); } bark( this, "Thou art already a member of our guild."); return( 0x00); } bark( this, "The fee for joining a guild is 500 gold coins."); setObjVar( speaker, "guildAskedToJoin", this); return( 0x00); } if( word == "resign" || ( word == "quit")) { if( hasObjVar( speaker, "guildMember")) { guild_id = getObjVar( speaker, "guildMember"); if( guild_id != my_guild) { bark( this, "Thou dost not belong to my guild!"); return( 0x00); } bark( this, "I accept thy resignation."); removeObjVar( speaker, "guildMember"); return( 0x00); } } if( word == "guild" || ( word == "guilds")) { phrases = "I am a Guildmaster of the " + guildName + ". Art thou interested in joining?"); bark( this, phrases); return( 0x00); } } return( 0x01);
}

gm.@give.source:
trigger give {
  int guild_type; if( hasObjVar( giver, "guildAskedToJoin")) { obj asked_guild = getObjVar( giver, "guildAskedToJoin"); if( asked_guild != this) { return( 0x01); } int value; int ok; ok = getResource( value, givenobj, "gold", 0x03, 0x02); if( ! ok) { return( 0x01); } if( value != 0x01F4) { return( 0x01); } ok = putObjContainer( givenobj, this); deleteObject( givenobj); string phrases = "Welcome to the " + guildName + "!"; guild_type = getObjVar( this, "guildMember"); if( guild_type == 0x03) { phrases = phrases + " Fellow thieves and beggars shall not bother thee now."; } else { phrases = phrases + " Thou shalt find that fellow members shall grant thee lower prices in shops."; } bark( this, phrases); setObjVar( giver, "guildMember", guild_type); return( 0x00); } return( 0x01);
}

grapevine.@use.source:
trigger use {
  int obj_type = getObjType( this); obj backpack = getBackpack( user); obj grapes; obj item; obj vine; int is_ew; int res_result; int fruit_qty; loc location = getLocation( this); switch( obj_type) { case 0x0D1E case 0x0D1F case 0x0D23 case 0x0D24 res_result = getResource( fruit_qty, this, "fruit", 0x03, 0x02); if( fruit_qty > 0x00) { grapes = createNoResObjectIn( 0x0D1A, backpack); returnResourcesToBank( this, 0x01, "fruit"); systemMessage( user, "You pick some grapes and put them in your backpack."); } else { systemMessage( user, "None of the grapes are ripe enough."); } return( 0x00); break; case 0x0D1B is_ew = 0x00; changeLoc( location, 0x00, 0x00 - 0x02, 0x00); break; case 0x0D1C is_ew = 0x00; changeLoc( location, 0x00, 0x02, 0x00); break; case 0x0D1D is_ew = 0x00; changeLoc( location, 0x00, 0x02, 0x00); break; case 0x0D20 is_ew = 0x01; changeLoc( location, 0x00 - 0x02, 0x00, 0x00); break; case 0x0D21 is_ew = 0x01; changeLoc( location, 0x02, 0x00, 0x00); break; case 0x0D22 is_ew = 0x01; changeLoc( location, 0x02, 0x00, 0x00); break; } if( is_ew) { vine = getFirstObjectOfType( location, 0x0D23); if( vine == NULL( )) { vine = getFirstObjectOfType( location, 0x0D24); } } else { vine = getFirstObjectOfType( location, 0x0D1E); if( vine == NULL( )) { vine = getFirstObjectOfType( location, 0x0D1F); } } if( vine == NULL( )) { return( 0x00); } res_result = getResource( fruit_qty, vine, "fruit", 0x03, 0x02); if( fruit_qty > 0x00) { grapes = createNoResObjectIn( 0x0D1A, backpack); returnResourcesToBank( vine, 0x01, "fruit"); systemMessage( user, "You pick some grapes and put them in your backpack."); } else { systemMessage( user, "None of the grapes are ripe enough."); } return( 0x00);
}

