grtheal.@targetobj.source:
trigger targetobj {
  if( ! confirm_and_clear_targeting( user, this)) { return( 0x01); } if( usedon == NULL( )) { return( 0x00); } if( check_visible_range( user, usedon, 0x0C)) { if( ! check_and_consume_reagents( user, this)) { return( 0x00); } if( try_cast_spell( user, getLocation( usedon), this)) { apply_greater_heal( user, usedon); } else { fizzle_spell( user); } } return( 0x00);
