grthealbase.apply_greater_heal.source:
function int apply_greater_heal(obj user, obj usedon) {
  int success = 0x00; if( is_targetable_mobile( usedon)) { int heal_amount; loc user_loc = getLocation( user); loc there = getLocation( usedon); faceHere( user, getDirectionInternal( user_loc, there)); doMobAnimation( usedon, 0x376A, 0x09, 0x20, 0x00, 0x00); sfx( there, 0x0202, 0x00); if( hasObjVar( this, "magicItemBonus")) { heal_amount = 0x19 + dice( 0x01, 0x0A); } else { heal_amount = ( getSkillLevel( user, 0x19) / 0x0A) * 0x04 + dice( 0x01, 0x0A); } int hp_before = getCurHP( usedon); addHP( usedon, heal_amount); int hp_after = getCurHP( usedon); heal_amount = hp_after - hp_before; string heal_str = heal_amount; if( isPlayer( user)) { systemMessage( user, heal_str + " points of damage have been healed."); } if( heal_amount != 0x00) { int notoriety_result = apply_spell_notoriety( user, usedon, 0x00, this); success = 0x01; } } schedule_cleanup( this); return( success);
}

guard.add_to_guard_list.source:
function void add_to_guard_list(obj m_target, obj guard) {
  if( ! isValid( m_target)) { return( ); } if( isInContainer( m_target)) { bark( m_target, "This is in a container and cannot be guarded."); return( ); } list guards; if( ! isInList( guardList, m_target)) { appendToList( guardList, m_target); } attachScript( m_target, "guarded"); if( hasObjVar( m_target, "myGuards")) { getObjListVar( guards, m_target, "myGuards"); } if( ! isInList( guards, guard)) { appendToList( guards, guard); } setObjVar( m_target, "myGuards", guards); if( 0x00) { bark( m_target, "I am now guarded."); } return;
}

guard.remove_from_guard_list.source:
function void remove_from_guard_list(obj m_target) {
  detachScript( m_target, "guarded"); while( isInList( guardList, m_target)) { if( 0x00) { bark( m_target, "I am not guarded anymore."); } removeSpecificItem( guardList, m_target); } return;
}

guard.guard_location.source:
