}

guard.remove_guard_at_location.source:
function void remove_guard_at_location(loc target_loc) {
  int found = 0x00; for( int i = 0x00; i < numInList( guardList); i = i + 0x01) { obj guarded_obj; guarded_obj = guardList [ i ]; loc obj_loc = getLocation( guarded_obj); if( obj_loc == target_loc) { found = 0x01; break; } } if( ! found) { return; } remove_from_guard_list( guarded_obj); deleteObject( guarded_obj); return;
}

guard.purge_invalid_guards.source:
function void purge_invalid_guards() {
