}

guard.update_patrol_list.source:
function void update_patrol_list(obj this) {
  debugMessage( "starting update of patrol path"); list new_patrol_list; int in_range = 0x01; for( int i = 0x00; i < numInList( guardList); i = i + 0x01) { obj guarded_obj; loc obj_loc = getLocation( guarded_obj); guarded_obj = guardList [ i ]; in_range = 0x01; int dist = getDistanceInTiles( getLocation( this), obj_loc); if( dist > myPatrolDistance) { if( ! isMobile( guarded_obj)) { remove_from_guard_list( guarded_obj); } in_range = 0x00; } if( in_range) { appendToList( new_patrol_list, guarded_obj); } } copyList( patrol_list, new_patrol_list); return;
}

guard.do_patrol_step.source:
function void do_patrol_step(obj this) {
  int myPatrolDelay = 0x1E; if( hasObjVar( this, "myPatrolDelay")) { myPatrolDelay = getObjVar( this, "myPatrolDelay"); } update_patrol_list( this); if( patrol_idx == numInList( patrol_list)) { patrol_idx = 0x00; } if( numInList( patrol_list) < 0x01) { debugMessage( "I have nothing in my list of items to patrol."); return( ); } loc where = getLocation( patrol_list [ patrol_idx ])); if( 0x00) { bark( this, "Walking to next patrol point."); } walkTo( this, where, 0x04); patrol_idx ++; int continue_patrol = 0x01; if( hasObjVar( this, "continuePatrol")) { continue_patrol = getObjVar( this, "continuePatrol"); } if( continue_patrol == 0x01) { callBack( this, myPatrolDelay, 0x17); } return;
}

