guard.@creation.source:
trigger creation {
  member int guardFromUse = 0x01; if( hasObjVar( this, "guardFromUse")) { guardFromUse = getObjVar( this, "guardFromUse"); if( 0x00) { bark( this, "Getting guard from use behavior."); } } member int guardFromProximity = 0x01; if( hasObjVar( this, "guardFromProximity")) { guardFromProximity = getObjVar( this, "guardFromProximity"); if( 0x00) { bark( this, "Getting guard from proximity behavior."); } } member int guardFromAttack = 0x01; if( hasObjVar( this, "guardFromAttack")) { guardFromAttack = getObjVar( this, "guardFromAttack"); if( 0x00) { bark( this, "Getting guard from attack behavior."); } } member int myGuardReaction = 0x01; if( hasObjVar( this, "myGuardReaction")) { myGuardReaction = getObjVar( this, "myGuardReaction"); if( 0x00) { bark( this, "Getting guard reaction."); } } member int myPatrolDistance = 0x1E; if( hasObjVar( this, "myPatrolDistance")) { myPatrolDistance = getObjVar( this, "myPatrolDistance"); if( 0x00) { bark( this, "Getting patrol distance."); } } member list guardList; member list patrol_list; member int patrol_idx; return( 0x01);
}

