guard.@callback(0x52).source:
trigger callback(0x52) {
  int should_react = 0x00; if( ! hasObjVar( this, "guardedObjectOffender")) { return( 0x00); } if( ! hasObjVar( this, "guardedObjectComplaint")) { return( 0x00); } if( ! hasObjVar( this, "guardedObjectSecond")) { return( 0x00); } if( ! hasObjVar( this, "guardedObjectSender")) { return( 0x00); } obj offender = getObjVar( this, "guardedObjectOffender"); int complaint_type = getObjVar( this, "guardedObjectComplaint"); obj corpse = getObjVar( this, "guardedObjectSecond"); obj sender = getObjVar( this, "guardedObjectSender"); removeObjVar( this, "guardedObjectOffender"); removeObjVar( this, "guardedObjectComplaint"); removeObjVar( this, "guardedObjectSecond"); removeObjVar( this, "guardedObjectSender"); if( offender == this) { return( 0x01); } if( hasObjListVar( this, "myBoss")) { list boss_list; getObjListVar( boss_list, this, "myBoss"); obj boss; for( int i = 0x00; i < numInList( boss_list); i ++) { boss = boss_list [ i ]; if( boss == offender) { if( 0x00) { bark( this, "My boss breached guard, so I don't care."); } return( 0x01); } } } if( 0x00) { string complaint_str = complaint_type; bark( this, complaint_str); } int hostile_act = 0x00; switch( complaint_type) { case 0x00 if( 0x00) { bark( this, "Guarding from use."); } if( guardFromUse == 0x01) { should_react = 0x01; } if( corpse != NULL( )) { if( 0x00) { bark( this, "Violated my owner's corpse!"); } hostile_act = 0x01; } setCriminal( offender, 0x01E0); break; case 0x01 if( 0x00) { bark( this, "Guarding from proximity!"); } if( guardFromProximity == 0x01) { should_react = 0x01; } break; case 0x02 if( 0x00) { bark( this, "Guarding from attack or theft!"); } if( guardFromAttack == 0x01) { should_react = 0x01; } hostile_act = 0x01; break; case 0x03 remove_from_guard_list( sender); stopFollowing( this); add_to_guard_list( corpse, this); if( 0x00) { bark( this, "My guarded mobile died, so I am guarding its corpse!"); } break; default if( 0x00) { bark( this, "Fell through to default type!"); } should_react = 0x00; break; } int force_attack; if( isMobile( sender) && hostile_act) { should_react = 0x01; force_attack = 0x01; } if( hostile_act) { should_react = 0x01; force_attack = 0x01; } if( ! should_react) { return( 0x00); } if( ! canSeeObj( this, sender)) { if( 0x00) { bark( this, "Cannot see the guarded object."); } return( 0x00); } if( ! isInList( guardList, sender)) { if( 0x00) { bark( this, "Not an object in my guardList."); } return( 0x00); } int reaction = myGuardReaction; if( force_attack) { if( 0x00) { bark( this, "Attack override!"); } reaction = 0x03; } switch( reaction) { case 0x01 if( hasObjVar( this, "isPet")) { string msg; msg = getName( this) + " looks somewhat annoyed."); bark( this, msg); } else { bark( this, "Please leave that alone."); } break; case 0x02 loc offender_loc = getLocation( offender); loc interpose_loc = interpose( offender_loc, getLocation( sender)); if( 0x00) { bark( this, "Interposing myself!"); } walkTo( this, interpose_loc, 0x02); break; case 0x03 if( 0x00) { bark( this, "Attacking the interloper!"); } attack( this, offender); break; default if( 0x00) { bark( this, "Couldn't interpret a guard reaction."); } return( 0x00); } return( 0x00);
}

