guarded.notify_guards.source:
function void notify_guards(int complaint, obj user, obj secondary) {
  int i; obj guard; list myGuards; list valid_guards; if( ! hasObjVar( this, "myGuards")) { return( ); } getObjListVar( myGuards, this, "myGuards"); for( i = 0x00; i < numInList( myGuards); i ++) { guard = myGuards [ i ]; if( isValid( guard)) { appendToList( valid_guards, guard); } } setObjVar( this, "myGuards", valid_guards); if( inJusticeRegion( getLocation( this))) { return( ); } for( i = 0x00; i < numInList( valid_guards); i ++) { guard = valid_guards [ i ]; setObjVar( guard, "guardedObjectOffender", user); setObjVar( guard, "guardedObjectComplaint", complaint); setObjVar( guard, "guardedObjectSecond", secondary); setObjVar( guard, "guardedObjectSender", this); shortCallback( guard, 0x01, 0x52); } return( );
}

