guilddeed.@use.source:
trigger use {
  member obj m_placer = user; member obj myHome; obj multi; if( hasObjVar( m_placer, "guildstoneId")) { barkTo( m_placer, m_placer, "You must resign from your current guild before founding another!"); return( 0x00); } multi = isAnyMultiBelow( getLocation( m_placer)); myHome = multi; if( myHome == NULL( )) { barkTo( m_placer, m_placer, "You can only place a guildstone in a house or on a ship."); return( 0x00); } if( ! mobile_owns_house( myHome, m_placer)) { barkTo( m_placer, m_placer, "You can only place a guildstone in a house or ship you own!"); return( 0x00); } if( has_guildstone( myHome)) { barkTo( m_placer, m_placer, "Only one guildstone may reside in a given house or ship."); return( 0x00); } member loc place = getLocation( m_placer); systemMessage( m_placer, "Enter the name of your new guild:"); textEntry( this, m_placer, 0x1B, 0x00, ""); return( 0x00);
}

guilddeed.@textentry(0x1B).source:
