guilddeed.@message(\"canChangeName\").source:
trigger message("canChangeName") {
  string name = args [ 0x00 ]; string msg = "A new guild hath been founded, to be called " + name + "!"; barkTo( m_placer, m_placer, msg); obj guild = createNoResObjectAt( 0x0ED5, place); if( ! try_set_guildstone( myHome, guild)) { barkTo( m_placer, m_placer, "Only one guildstone may reside in on a given house or ship."); deleteObject( guild); return( 0x00); } setObjVar( guild, "guildName", name); setObjVar( guild, "lookAtText", "The Guildstone for " + name); mark_for_multi_delete( guild); setObjVar( guild, "myHome", myHome); attachScript( guild, "guildstone"); deleteObject( this); return( 0x01);
