trigger message("updateGuildInfo") {
  int still_member = args [ 0x00 ]; string new_name = args [ 0x01 ]; string new_abbr = args [ 0x02 ]; string new_title = args [ 0x03 ]; if( new_name != guildName( )) { systemMessage( this, "The name of your guild has changed from " + guildName( ) + " to " + new_name + "."); setObjVar( this, "guildName", new_name); } if( new_abbr != get_guild_abbreviation( )) { systemMessage( this, "Your guild abbreviation has changed from " + get_guild_abbreviation( ) + " to " + new_abbr + "."); setObjVar( this, "guildAbbreviation", new_abbr); } if( new_title != myGuildTitle( )) { systemMessage( this, "You have been given a new guild title: " + new_title + "."); setObjVar( this, "myGuildTitle", new_title); } if( ! still_member) { systemMessage( this, "You have been dismissed from " + guildName( ) + "."); cleanup( this); } return( 0x01);
