harbormaster.dock_ship.source:
function obj dock_ship(obj ship, loc where) {
  list objects_on_deck; getObjectsOnMulti( objects_on_deck, ship); if( numInList( objects_on_deck) > 0x00) { return( NULL( )); } obj shiphold = NULL( ); if( hasObjVar( ship, "myshiphold")) { shiphold = getObjVar( ship, "myshiphold"); } if( shiphold != NULL( )) { list hold_contents; getContents( hold_contents, shiphold); int hold_count = numInList( hold_contents); if( hold_count > 0x00) { return( NULL( )); } } obj claim_ticket = createGlobalObjectAt( 0x0E76, where); if( claim_ticket == NULL( )) { return( NULL( )); } setType( claim_ticket, 0x14F2); setStatus( claim_ticket, 0x80, 0x01); int ship_type = 0x00; if( hasObjVar( ship, "myshiptype")) { ship_type = getObjVar( ship, "myshiptype"); setObjVar( claim_ticket, "myshiptype", ship_type); } if( hasObjVar( ship, "mymultiname")) { string ship_name = getObjVar( ship, "mymultiname"); setObjVar( claim_ticket, "mymultiname", ship_name); } set_claim_ticket_desc( claim_ticket, ship, where); setObjVar( claim_ticket, "claimloc", where); setObjVar( claim_ticket, "shipobj", ship); attachScript( claim_ticket, "shipclaim"); int ticket_put_result = putObjContainer( ship, claim_ticket); return( claim_ticket);
}

