  list words; split( words, arg); if( isInList( words, "dock")) { prompt_dock_ship( speaker, this); return( 0x00); } else { if( isInList( words, "job")) { bark( this, "I am a harbormaster.  I dock ships for a fee."); return( 0x00); } } return( 0x01);
}

harbormaster.@targetobj.source:
trigger targetobj {
  if( usedon == NULL( )) { return( 0x00); } if( amtGoldInBank( user) < 0x19) { barkTo( this, user, "Thou dost not have 25 gold in thy bank account."); return( 0x00); } if( ! isValid( usedon)) { return( 0x00); } if( getDistanceInTiles( getLocation( this), getLocation( usedon)) > 0x64) { barkTo( this, user, "That is too far away."); return( 0x00); } if( isMultiComp( usedon) && ( hasObjVar( getMultiSlaveId( usedon), "myshiptype"))) { obj ship = getMultiSlaveId( usedon); if( user_has_ship_key( ship, user)) { obj claim_ticket = dock_ship( ship, getLocation( this)); if( claim_ticket == NULL( )) { barkTo( this, user, "I could not dock the ship."); barkTo( this, user, "Make sure the deck is clear and the hold is empty."); } else { int fee_result = withdrawAndDestroy( user, 0x19); int move_result = toMobile( claim_ticket, user); barkTo( this, user, "Here is your claim ticket.  I suggest you store it in your safety deposit box for safety."); } } else { barkTo( this, user, "You must have the key to the ship you wish to dock."); } } else { barkTo( this, user, "That is not a ship!"); } return( 0x00);
}

