harm.@targetobj.source:
trigger targetobj {
  if( ! confirm_and_clear_targeting( user, this)) { return( 0x01); } if( usedon == NULL( )) { return( 0x00); } if( check_target_in_range( user, usedon, 0x00)) { if( ! check_and_consume_reagents( user, this)) { return( 0x00); } if( try_cast_spell( user, getLocation( usedon), this)) { if( hasScript( usedon, "reflctor")) { doMobAnimation( usedon, 0x37B9, 0x0A, 0x05, 0x00, 0x00); apply_harm( usedon, user, 0x01); detachScript( usedon, "reflctor"); } else { apply_harm( user, usedon, 0x00); } } else { fizzle_spell( user); } } return( 0x00);
