healbase.apply_heal.source:
function int apply_heal(obj user, obj usedon) {
  int success = 0x00; if( is_targetable_mobile( usedon)) { int heal_amount; loc user_loc = getLocation( user); loc there = getLocation( usedon); faceHere( user, getDirectionInternal( user_loc, there)); doMobAnimation( usedon, 0x376A, 0x09, 0x20, 0x00, 0x00); sfx( there, 0x01F2, 0x00); if( hasObjVar( this, "magicItemBonus")) { heal_amount = 0x05 + dice( 0x01, 0x06); } else { heal_amount = ( ( getSkillLevel( user, 0x19) / 0x0A) + dice( 0x01, 0x06)); } int hp_before = getCurHP( usedon); addHP( usedon, heal_amount); int hp_after = getCurHP( usedon); heal_amount = hp_after - hp_before; string heal_str = heal_amount; if( isPlayer( user)) { systemMessage( user, heal_str + " points of damage have been healed."); } if( heal_amount > 0x00) { int notoriety_result = apply_spell_notoriety( user, usedon, 0x00, this); success = 0x01; } } schedule_cleanup( this); return( success);
}

healer.@enterrange(0x03).source:
trigger enterrange(0x03) {
  if( ! canSeeObj( this, target)) { return( 0x01); } if( isDead( target)) { loc target_loc = getLocation( target); loc self_loc = getLocation( this); int z_diff = getZ( target_loc) - getZ( self_loc); if( z_diff < 0x00) { z_diff = z_diff * ( 0x00 - 0x01); } if( z_diff > 0x04) { return( 0x01); } if( isOnAnyMulti( target)) { return( 0x01); } if( ! isFacingPerson( this, target)) { int dir = getDirection( self_loc, target_loc); faceHere( this, dir); } if( ! getCompileFlag( 0x01)) { if( getNotorietyLevel( this) > ( 0x00 - 0x01)) { if( getNotorietyLevel( target) < ( 0x00 - 0x02)) { bark( this, "Thou'rt not a decent and good person. I shall not resurrect thee."); return( 0x01); } if( getNotorietyLevel( target) < 0x00) { bark( this, "Thou hast strayed from the path of virtue, but thou still deservest a second chance."); } } } else { if( getKarmaLevel( this) > ( 0x00 - 0x01)) { if( isMurderer( target)) { bark( this, "Thou'rt not a decent and good person. I shall not resurrect thee."); return( 0x01); } if( getKarmaLevel( target) < 0x00) { bark( this, "Thou hast strayed from the path of virtue, but thou still deservest a second chance."); } } } animateMobile( this, 0x10, 0x07, 0x01, 0x00, 0x00); doMobAnimation( this, 0x376A, 0x09, 0x20, 0x00, 0x00); sfx( getLocation( this), 0x01F2, 0x00); offer_resurrect( this, target, 0x01, "It is possible for you to be resurrected here by this healer. Do you wish to try?"); return( 0x00); } return( 0x01);
}

