help.check_gm_available.source:
function int check_gm_available(obj it) {
  if( ! getGMCallStatus( )) { systemMessageHued( this, 0x35, "We are sorry, but currently a GM is unavailable to answer your call.  Our in-game support hours are 2:00pm-12:00am CST, although we are monitoring the servers for problems during these off peak times.  Please try again during these times."); end_help_session( this, 0x00); return( 0x00); } return( 0x01);
}

help.increment_call_count.source:
function void increment_call_count(obj player, int priority) {
  if( priority == 0x01) { int num = 0x00; if( hasObjVar( player, "calls")) { num = getObjVar( player, "calls"); } num = num + 0x01; setObjVar( player, "calls", num); } return( );
}

help.submit_help_request.source:
function void submit_help_request(obj player, int call_type, string category, string text) {
  string message = category; concat( message, ": "); string loc_str; loc location = getLocation( player); loc_str = "("; loc_str = loc_str + getX( location); concat( loc_str, " "); loc_str = loc_str + getY( location); concat( loc_str, " "); loc_str = loc_str + getZ( location); concat( loc_str, ") "); concat( message, loc_str); concat( message, text); addHelpRequestToQueue( player, call_type, 0x00, message); increment_call_count( player, call_type); return( );
}

help.close_if_invalid.source:
function void close_if_invalid(obj player, int num, int cancelled) {
  if( ( num == 0x00) || ( ! isValid( player))) { end_help_session( this, cancelled); } return( );
}

help.schedule_timeout.source:
function void schedule_timeout(obj player) {
  callback( player, 0x78, 0x70); return( );
}

help.show_main_menu.source:
function void show_main_menu(obj player) {
  list options; appendToList( options, 0x00); appendToList( options, "CHARACTER IS PHYSICALLY STUCK:  This type of call can only be handled by a Game Master.  Game Master hours are 2:00pm to 12:00am CST."); appendToList( options, 0x01); appendToList( options, "ANOTHER PLAYER IS HARASSING ME:  Again, the only way for us to verify this kind of issue directly is for you to call a Game Master.  If the harassment occurs outside of Game Master hours, please send a message to our e-mail support."); appendToList( options, 0x02); appendToList( options, "CHARACTER CAN NOT CONTINUE: If your character is suffering from an error which is considered drastic and is preventing you from continuing within the game, please page a Game Master during the posted hours or write to our e-mail support."); appendToList( options, 0x03); appendToList( options, "CONTINUE:  If your choice was not listed here, select this option."); appendToList( options, 0x04); appendToList( options, "DONE"); selectType( player, player, 0x64, "Please remember, Game Masters are only available to help with the following types of calls:  character cannot move, you are being harassed, or your character cannot continue.  Please choose the area in which you require assistance from below.", options); return( );
}

help.show_tech_billing_menu.source:
function void show_tech_billing_menu(obj player) {
  list options; appendToList( options, 0x00); appendToList( options, "TECHNICAL SUPPORT:  Sound or video problems, client crashes, lag, latency, or other technical issues.  You may try to resolve these issues through our web page trouble-shooter, email, or you may speak to a technical support representative directly."); appendToList( options, 0x01); appendToList( options, "BILLING ISSUES:  If you cannot log into the game, if you believe your billing statement is in error, or just have general billing questions."); appendToList( options, 0x02); appendToList( options, "PREVIOUS:  If the option you need was not listed above."); appendToList( options, 0x03); appendToList( options, "CONTINUE: If the option you need was not listed above, nor on the previous menu."); appendToList( options, 0x04); appendToList( options, "DONE"); selectType( player, player, 0x65, "Please select from the following options:", options); return( );
}

help.show_general_help_menu.source:
function void show_general_help_menu(obj player) {
  list options; appendToList( options, 0x00); appendToList( options, "GENERAL HINTS / GAMEPLAY QUESTIONS:  If you need a hint or just a push in the right direction, select this option."); appendToList( options, 0x01); appendToList( options, "REQUEST LATEST GAME INFORMATION:  We continuously update all new information regarding Ultima Online, plus any information about upcoming updates on our web page."); appendToList( options, 0x02); appendToList( options, "BUG SUBMISSION / LOST ITEMS:  You may submit any bugs which have adversely, or even beneficially, affected your character to our web page."); appendToList( options, 0x03); appendToList( options, "PREVIOUS:  If the option you need was not listed above."); appendToList( options, 0x04); appendToList( options, "DONE"); selectType( player, player, 0x66, "Please select from the following options:", options); return( );
