function int create_and_assign_key(obj user, obj house, obj door, obj sign, int bank) {
  loc user_loc = getLocation( user); loc door_loc = getLocation( door); moveDir( door_loc, 0x04); list key_types = 0x100E, 0x100F, 0x1010, 0x1013; int num = random( 0x00, ( numInList( key_types) - 0x01)); int key_type = key_types [ num ]; obj key = NULL( ); obj container = NULL( ); if( bank) { fixBank( user); container = getItemAtSlot( user, 0x1D); if( container == NULL( )) { container = getBackpack( user); bank = 0x00; } } else { container = getBackpack( user); } if( container == NULL( )) { key = createGlobalObjectAt( key_type, user_loc); barkTo( user, user, "A house key is now at my feet."); } else { key = createGlobalObjectIn( key_type, container); if( bank) { barkTo( user, user, "A house key is now in my safety deposit box."); } else { barkTo( user, user, "A house key is now in my backpack."); } } if( key == NULL( )) { bark( user, "Ack, a key could not be created!"); deleteObject( house); return( 0x00); } attachScript( key, "key"); list doors; if( hasObjVar( house, "myhousedoors")) { getObjListVar( doors, house, "myhousedoors"); } int count = numInList( doors); for( int i = 0x00; i < count; i ++) { door = doors [ i ]; attach_lockable_to_key( door, key); } if( sign != NULL( )) { attach_lockable_to_key( sign, key); } attachScript( key, "housekey"); return( 0x01);
}

