function int initialize_placed_house(obj house, obj deed, obj user) {
  transferAllResources( house, deed); reset_decay( house); obj door = NULL( ); if( hasObjVar( house, "myhousedoor")) { door = getobjvar_obj( house, "myhousedoor"); } obj sign = NULL( ); if( hasObjVar( house, "myhousesign")) { sign = getobjvar_obj( house, "myhousesign"); } string creator_name = getName( user); if( sign != NULL( )) { setObjVar( sign, "creatorId", user); setObjVar( sign, "creatorName", creator_name); } else { setObjVar( house, "creatorId", user); setObjVar( house, "creatorName", creator_name); } int key_result = create_and_assign_key( user, house, door, sign, 0x00); key_result = create_and_assign_key( user, house, door, sign, 0x01); if( house != NULL( )) { deleteObject( deed); } return( 0x01);
}

