housekey.lock_down.source:
function void lock_down(obj it) {
  attachScript( it, "lockdown"); return( );
}

housekey.release_lockdown.source:
function void release_lockdown(obj it) {
  detachScript( it, "lockdown"); return( );
}

housekey.is_locked_down.source:
function int is_locked_down(obj it) {
  return( hasScript( it, "lockdown"));
}

housekey.key_matches_house.source:
function int key_matches_house(obj key, obj house) {
  list unlocks; getObjListVar( unlocks, key, "whatIUnlock"); list doors; if( hasObjVar( house, "myhousedoors")) { getObjListVar( doors, house, "myhousedoors"); } int door_count = numInList( doors); for( int i = 0x00; i < door_count; i ++) { if( isInList( unlocks, doors [ i ])) { return( 0x01); } } return( 0x00);
}

housekey.toggle_lockdown.source:
function int toggle_lockdown(obj key, obj user_obj, obj it) {
  loc where = getLocation( user_obj); obj house = get_nearby_house_for_user( user_obj, where); if( ! isValid( house)) { systemMessage( user_obj, "You are not around your house."); return( 0x00); } if( ! key_matches_house( key, house)) { systemMessage( user_obj, "This key is not for this house."); return( 0x00); } if( is_locked_down( it)) { release_lockdown( it); systemMessage( user_obj, "You release that locked down object."); } else { lock_down( it); systemMessage( user_obj, "You lock that down."); } return( 0x01);
}

housekey.is_locked.source:
function int is_locked(obj it) {
  return( hasScript( it, "locked"));
}

housekey.key_unlocks_item.source:
function int key_unlocks_item(obj key, obj it) {
  list unlocks; getObjListVar( unlocks, key, "whatIUnlock"); return( isInList( unlocks, it));
}

housekey.@creation.source:
trigger creation {
  setObjVar( this, "predesc", "a house key"); setObjVar( this, "lookAtText", "a house key"); return( 0x01);
}

housesign.clear_lock.source:
function void clear_lock(obj it) {
  if( hasScript( it, "locked")) { detachScript( it, "locked"); } if( hasObjVar( it, "isLocked")) { removeObjVar( it, "isLocked"); } if( hasObjVar( it, "lockLevel")) { removeObjVar( it, "lockLevel"); } return( );
}

housesign.@creation.source:
trigger creation {
  clear_lock( this); obj house = getMultiSlaveId( this); setObjVar( house, "myhousesign", this); return( 0x01);
}

housesign.@use.source:
trigger use {
  obj house = getMultiSlaveId( this); if( has_house_key( house, user) || isEditing( user)) { systemMessage( user, "What dost thou wish the sign to say?"); textEntry( this, user, 0x17, 0x00, ""); } return( 0x00);
}

housesign.@textentry(0x17).source:
trigger textentry(0x17) {
  if( button == 0x00) { return( 0x00); } obj house = getMultiSlaveId( this); if( has_house_key( house, sender) || isEditing( sender)) { if( text == "") { if( has_name( house)) { clear_name( house); barkTo( this, sender, "I now say nothing."); } } else { string reply = "I now say "; concat( reply, text); concat( reply, "."); barkTo( this, sender, reply); set_name( house, text); } } return( 0x00);
}

housesign.@lookedat.source:
trigger lookedat {
  obj multi = getMultiSlaveId( this); if( has_name( multi)) { barkTo( this, looker, get_custom_multi_name( multi)); bark_decay_status( this, looker, "house"); return( 0x00); } bark_decay_status( this, looker, "house"); return( 0x01);
}

housestuff.get_multi_type_id.source:
function int get_multi_type_id(int house_type, int state) {
  return( 0x64 + ( house_type * 0x02) + state);
}

housestuff.set_house_state.source:
function int set_house_state(obj house, int state) {
  string msg; int myhousetype = getObjVar( house, "myhousetype"); int gump_id = get_multi_type_id( myhousetype, state); int result = recycleMulti( house, gump_id); if( result > 0x00) { setObjVar( house, "myhousestate", state); } return( result);
}

housestuff.place_house.source:
function obj place_house(int house_type, loc place) {
  placement_z_offset = ( 0x00 - 0x06); int gump_id = get_multi_type_id( house_type, 0x00); if( areMobilesInMultiArea( gump_id, place)) { placement_z_offset = ( 0x00 - 0x09); return( NULL( )); } obj house = makeMultiInstCheck( place, gump_id, 0x08, ( 0x00 - 0x03), placement_z_offset, 0x00, 0x00, 0x00); if( house != NULL( )) { setObjVar( house, "myhousetype", house_type); setObjVar( house, "myhousestate", 0x00); string time_str; getCurrentTimeStr( time_str); setObjVar( house, "creationtime", time_str); } return( house);
}

housestuff.change_house_state.source:
function int change_house_state(obj house, int new_state) {
  int current_state = getObjVar( house, "myhousestate"); if( new_state != current_state) { return( set_house_state( house, new_state)); } return( 0x00);
}

housestuff.get_house_base_value.source:
function int get_house_base_value(int house_type) {
  int gump_id = get_multi_type_id( house_type, 0x00); return( getNumInMultiType( gump_id) * 0xC8);
}

housestuff.adjust_placement_loc.source:
function loc adjust_placement_loc(int house_type, loc place) {
  loc min_extent; loc max_extent; int gump_id = get_multi_type_id( house_type, 0x00); if( getMultiExtents( gump_id, min_extent, max_extent)) { setY( place, getY( place) - getY( max_extent)); } return( place);
}

housestuff.mark_for_multi_delete.source:
function void mark_for_multi_delete(obj it) {
  setObjVar( it, "multiDelete", 0x01); return( );
}

human.handle_armageddon.source:
function int handle_armageddon(int level) {
  if( level < 0x02) { return( 0x01); } if( hasScript( this, "stables")) { return( 0x01); } if( isShopkeeper( this)) { return( 0x00); } return( 0x01);
}

human.has_scavenge_target.source:
function int has_scavenge_target(obj this) {
  loc here = getLocation( this); int in_range = objIsInRange( here, 0x04); if( ! in_range) { if( 0x00) { debugMessage( "Nothing nearby to scavenge."); } return( 0x00); } return( 0x01);
}

human.scavenge_nearby_item.source:
function void scavenge_nearby_item(obj this) {
  list nearby_objects; getObjectsInRange( nearby_objects, getLocation( this), 0x04); int idx = random( 0x00, numInList( nearby_objects) - 0x01); obj m_target = nearby_objects [ idx ]; if( ! is_tile_clear( this, m_target)) { return( ); } if( getWeight( m_target) > 0x14) { if( 0x00) { bark( this, "Tried to scavenge something too heavy. :P"); } return( ); } if( ! isMoveable( m_target, this)) { return( ); } if( is_guarded( this, m_target)) { return( ); } if( getObjType( m_target) < 0x03) { return( ); } if( hasObjVar( this, "ScavengeLastItemGotten")) { obj last_item = getObjVar( this, "ScavengeLastItemGotten"); if( hasObj( this, last_item)) { deleteObject( last_item); } } member obj scavenge_target = m_target; walkTo( this, getLocation( m_target), 0x08); return( );
}

