  int cur_type = getObjType( keyring); list contents; getContents( contents, keyring); int num = numInList( contents); num = num + add; int newtype; if( num < 0x00) { newtype = 0x1011; } else { switch( num) { case 0x00 newtype = 0x1011; break; case 0x01 case 0x02 newtype = 0x1769; break; case 0x03 case 0x04 newtype = 0x176A; break; default newtype = 0x176B; break; } } if( cur_type != newtype) { setType( keyring, newtype); } return;
}

