  obj container = getItemAtSlot( user, 0x15); if( container == NULL( )) { return( 0x01); } if( ! isContainer( container)) { return( 0x01); } list keys; getContents( keys, keyring); int num = numInList( keys); for( int i = 0x00; i < num; i ++) { obj key = keys [ i ]; int result = putObjContainer( key, container); } update_keyring_type( keyring, 0x00); systemMessage( user, "You open the keyring."); return( 0x01);
}

