function int try_lock_unlock(obj keyring, obj user, obj usedon) {
  list keys; getContents( keys, keyring); int num = numInList( keys); for( int i = 0x00; i < num; i ++) { obj key = keys [ i ]; if( can_unlock( key, usedon)) { if( toggle_lock( key, usedon)) { barkTo( usedon, user, "You lock " + getName( usedon) + "."); } else { barkTo( usedon, user, "You unlock " + getName( usedon) + "."); } return( 0x01); } } barkTo( usedon, user, "You do not have a key for " + getName( usedon) + "."); return( 0x01);
