  if( isValid( beacon_first)) { deleteObject( beacon_first); } switch( sequence_step) { case 0x01 beacon_first = createGlobalObjectAt( 0x1EEC, loc_first); shortcallback( marker, 0x02, 0x2F); sequence_step = 0x02; break; case 0x02 speaker_first = createGlobalObjectAt( 0x1EF3, loc_first); barkToHued( speaker_first, subject, 0x22, "Start as the sun and move with time. Consider A FEW before the elements are placed, for a lack of order can bring Relvinian's bane."); sequence_step = 0x03; callback( marker, 0x09, 0x2F); break; case 0x03 deleteObject( speaker_first); beacon_second = createGlobalObjectAt( 0x1EEC, loc_second); sequence_step = 0x04; shortcallback( marker, 0x02, 0x2F); break; case 0x04 deleteObject( beacon_second); speaker_second = createGlobalObjectAt( 0x1EF3, loc_second); barkToHued( speaker_second, subject, 0x22, "Once thy decision has been made, proceed to the altar and between the flames pronounce the Master's name."); sequence_step = 0x05; callback( marker, 0x09, 0x2F); break; case 0x05 deleteObject( speaker_second); sequence_active = 0x00; break; default break; } return( 0x00);
}

