mapmaking.@typeselected(0x1A).source:
trigger typeselected(0x1A) {
  bark( target_map, "Making the map now."); if( hasObjVar( target_map, "valueless")) { removeObjVar( this, "valueless"); } if( ! testSkill( this, 0x0C)) { clear_map_vars( target_map); setMapProperties( target_map, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00); barkTo( target_map, this, "Thy trembling hand results in an unusable map."); if( random( 0x00, 0x03) == 0x01) { deleteObject( target_map); } return( 0x00); } int half_extent; int scale; int skill = getSkillLevel( this, 0x0C); loc origin = getLocation( this); switch( objtype) { case 0x196F scale = 0x04; break; case 0x1970 scale = 0x08; break; case 0x1971 scale = 0x14; break; case 0x1972 scale = 0x28; origin = 0x0580, 0x0680, 0x00; break; default scale = 0x01; break; } if( skill < 0x0A) { skill = 0x0A; } half_extent = ( ( skill * scale) / 0x02) + 0x40; int half_size = half_extent / 0x02; if( scale > 0x0A) { half_size = half_size - ( half_size / 0x03); } if( half_size < 0xC8) { half_size = 0xC8; } if( half_size > 0x0190) { half_size = 0x0190; } if( half_size > half_extent) { half_extent = half_size; } int disp_w = half_size; int disp_h = half_size; int cx = getX( origin); int cy = getY( origin); int min_x = cx - half_extent; int min_y = cy - half_extent; int max_x = cx + half_extent; int max_y = cy + half_extent; if( min_x < 0x00) { min_x = 0x00; } if( max_x > 0x13FF) { max_x = 0x144F; } if( min_y < 0x00) { min_y = 0x00; } if( max_y > 0x0FFF) { max_y = 0x0FFF; } clear_map_vars( target_map); setMapProperties( target_map, 0x00, min_x, min_y, max_x, max_y, disp_w, disp_h); setObjVar( target_map, "wasHandMade", 0x01); barkTo( target_map, this, "With great care, thou dost make a chart of the geography."); return( 0x00);
}

