  begin_spell_cast( this, user); return( 0x00);
}

nrgyvrtx.@message(\"castspell\").source:
trigger message("castspell") {
  obj user = get_caster_2( this, args); if( ! isValid( user)) { return( 0x00); } begin_targeting( user, this); targetLoc( user, this); return( 0x00);
}

nrgyvrtx.@targetloc.source:
trigger targetloc {
  if( ! confirm_and_clear_targeting( user, this)) { return( 0x01); } if( ! isInMap( place)) { return( 0x00); } if( canSeeLoc( user, place) == 0x01) { if( ! check_and_consume_reagents( user, this)) { return( 0x00); } if( try_cast_spell( user, place, this)) { summon_energy_vortex( user, place); } else { fizzle_spell( user); } } else { systemMessage( user, "Target cannot be seen. Try again."); targetLoc( user, this); } return( 0x00);
}

nrgyvrtx.@callback(0x49).source:
trigger callback(0x49) {
  obj user = getObjVar( this, "user"); obj target = getObjVar( this, "target"); loc target_loc = getLocation( target); summon_energy_vortex( user, target_loc); return( 0x00);
}

nrgyvrtxbase.summon_energy_vortex.source:
function int summon_energy_vortex(obj user, loc place) {
  int success = 0x00; int damage; loc user_loc = getLocation( user); faceHere( user, getDirectionInternal( user_loc, place)); list objects_at_target; getObjectsAt( objects_at_target, place); if( numInList( objects_at_target) == 0x00) { if( ! getCompileFlag( 0x01)) { report_loc_aggression( user, summon_loc, 0x02, 0x00); } summon_loc = place; obj vortex = createGlobalNPCAt( 0x023D, summon_loc, 0x00); if( vortex != NULL( )) { success = 0x01; copyControllerInfo( vortex, user); attachScript( vortex, "vortexai"); attachScript( vortex, "destcrea"); setObjVar( vortex, "summonDifficulty", 0x0320); sfx( summon_loc, 0x0212, 0x00); callback( vortex, 0x5A, 0x08); int state_result = doNPCHandleStates( vortex); } } else { barkTo( user, user, "That location is blocked."); } schedule_cleanup( this); return( success);
}

objinfo.@use.source:
trigger use {
  targetObj( user, this); return( 0x01);
}

objinfo.@targetobj.source:
trigger targetobj {
  string num; string msg = objToStr( usedon); int val = getValue( usedon); num = val; concat( msg, " "); concat( msg, num); barkTo( usedon, user, msg); msg = "weight: "; num = getWeight( usedon); concat( msg, num); bark( usedon, msg); loc blah = getLocation( usedon); bark( usedon, "(" + getX( blah) + "," + getY( blah) + "," + getZ( blah) + ")"); return( 0x01);
}

obscenetest.@speech(\"*\").source:
trigger speech("*") {
  if( isObscene( arg)) { systemMessage( this, "obscene"); } else { systemMessage( this, "okay"); } return( 0x00);
}

oilflask.@use.source:
