  if( usedon == NULL( )) { return( 0x00); } int obj_type = getObjType( usedon); switch( obj_type) { case 0x0A18 case 0x0A1D case 0x0A25 case 0x0A15 case 0x0A1A case 0x0A22 setObjVar( usedon, "fuel", 0x64); destroyOne( this); break; } return( 0x00);
}

