  list nearby_objects; getObjectsInRange( nearby_objects, getLocation( this), 0x0A); int rand_idx = random( 0x00, numInList( nearby_objects) - 0x01); obj candidate_item = nearby_objects [ rand_idx ]; if( ! is_tile_clear( this, candidate_item)) { return( ); } if( getWeight( candidate_item) > 0x14) { if( 0x00) { bark( this, "Tried to scavenge something too heavy. :P"); } return( ); } if( is_guarded( this, candidate_item)) { return( ); } if( getObjType( candidate_item) == 0x00) { return( ); } if( hasObjVar( this, "ScavengeLastItemGotten")) { obj last_item = getObjVar( this, "ScavengeLastItemGotten"); if( hasObj( this, last_item)) { deleteObject( last_item); } } member obj scavenge_target = candidate_item; walkTo( this, getLocation( candidate_item), 0x08); return( );
}

