function int handle_name_speech(obj this, obj speaker, string arg) {
  list args; int i; int found; if( ! check_convo_eligibility( this, speaker, arg)) { return( 0x01); } split( args, arg); list known_names; list memoryRecent; list memoryNotoriety; if( hasObjVar( this, "memoryRecent")) { getObjListVar( memoryRecent, this, "memoryRecent"); } if( hasObjVar( this, "memoryNotoriety")) { getObjListVar( memoryNotoriety, this, "memoryNotoriety"); } copyList( known_names, memoryRecent); if( 0x00) { debugMessage( "Added recent memory to the names check list."); } list memory_entry; obj person; int num_entries = numInList( memoryNotoriety); for( i = 0x00; i < num_entries; i ++) { copyList( memory_entry, memoryNotoriety [ i ]); person = memory_entry [ 0x00 ]; appendToList( known_names, person); if( 0x00) { debugMessage( "Added a name from fame memory to the names check list."); } } int j; found = 0x00; string spoken_word; string known_name; for( i = 0x00; i < numInList( args); i ++) { spoken_word = args [ i ]; for( j = 0x00; j < numInList( known_names); j ++) { known_name = getName( known_names [ j ]); if( spoken_word == known_name) { found = 0x01; break; } } } if( ! found) { found = check_murder_witness( arg); } if( found) { if( 0x00) { debugMessage( "Recognized a name in speech."); } spoken_word = getName( known_names [ j ]); string speaker_name = getName( speaker); if( spoken_word != speaker_name) { replyTo( this, known_names [ j ], "@InternalNameRecognition"); begin_convo_pause( this); if( 0x00) { debugMessage( "doing Convo Pause"); } obj recognized = known_names [ j ]; string msg = getHeShe( recognized) + " is " + getDirection( getLocation( this), getLocation( recognized)) + "."; toUpper( msg, 0x00, 0x01); bark( this, msg); if( getDistance( getLocation( this), getLocation( recognized)) == "right here") { msg = "Just turn around and look."; } else { if( getDistance( getLocation( this), getLocation( recognized)) == "a long journey") { msg = "Just turn around and look."; } else { msg = getHeShe( recognized) + " is " + getDistance( getLocation( this), getLocation( recognized)) + " from here."; toUpper( msg, 0x00, 0x01); bark( this, msg); } } return( 0x00); } if( 0x00) { bark( this, "Speaker asked about himself."); } } return( 0x01);
