  string need_str; if( hasObjVar( this, "CurrentNeedString")) { if( 0x00) { bark( this, "I had just stored my need."); } need_str = getObjVar( this, "CurrentNeedString"); removeObjVar( this, "CurrentNeedString"); setConvoRet( need_str); return( 0x00); } list food_resources; list desire_resources; list all_resources; int ok; ok = getResourcesOnObj( this, 0x00, food_resources); if( ok) { copyList( food_resources, all_resources); } ok = getResourcesOnObj( this, 0x02, desire_resources); string resource; if( ok) { if( numInList( all_resources) > 0x00) { for( int i = 0x00; i < numInList( desire_resources); i ++) { resource = desire_resources [ i ]; appendToList( all_resources, resource); } } } if( numInList( all_resources) < 0x01) { setConvoRet( "food"); return( 0x00); } int idx; idx = ( random( 0x01, numInList( all_resources))); idx --; resource = all_resources [ idx ]; int bar = getResource( ok, this, resource, 0x00, 0x00); if( bar) { resource = getResourceName( resource, 0x00); } else { resource = getResourceName( resource, 0x02); } setConvoRet( resource); return( 0x00);
}

old_human.@convofunc(\"Leave\").source:
trigger convofunc("Leave") {
  int direction = getDirectionInternal( getLocation( talker), getLocation( this)); faceHere( this, direction); removeObjVar( this, "lastSpokeTo"); setConvoRet( ""); if( hasObjVar( this, "myBoss")) { list boss_list; getObjListVar( boss_list, this, "myBoss"); if( ! isInList( boss_list, talker)) { stopFollowing( this); } } return( 0x00);
}

old_human.@convofunc(\"Attack\").source:
trigger convofunc("Attack") {
  walkTo( this, getLocation( talker), 0x09); attack( this, talker); setConvoRet( ""); return( 0x00);
}

old_human.@convofunc(\"getHint\").source:
trigger convofunc("getHint") {
  setConvoRet( get_rumor( this, talker)); return( 0x00);
}

old_human.@sawdeath.source:
trigger sawdeath {
  list witness_list; if( hasObjVar( this, "myMurderWitnessList")) { getObjListVar( witness_list, this, "myMurderWitnessList"); } list murder_entry; if( ( ! isHuman( victim)) || ( ! isHuman( attacker)) || ( isGuard( attacker))) { debugMessage( "Saw death, one participant is not human, or attack is a guard."); return( 0x00); } if( ! canSeeObj( this, attacker)) { debugMessage( "Cannot see attacker."); return( 0x00); } if( ! canSeeObj( this, victim)) { debugMessage( "Cannot see victim."); return( 0x00); } murder_entry = attacker, victim; appendToList( witness_list, murder_entry); if( numInList( witness_list) > 0x0A) { removeSpecificItem( witness_list, 0x00); } return( 0x00);
}

old_human.@give.source:
trigger give {
  if( mobileWillBuy( this, givenobj)) { bark( this, "I might be interested in buying this of thee."); intRet( 0x00); return( 0x01); } if( hasObjVar( this, "trainerSkillToTeach")) { if( 0x00) { bark( this, "I am teaching!"); } if( hasObjVar( giver, "trainingSkillToLearn")) { if( 0x00) { bark( this, "And the asker is learning."); } int skill_id = getObjVar( this, "trainerSkillToTeach"); int learn_skill = getObjVar( giver, "trainingSkillToLearn"); removeObjVar( this, "trainerSkillToTeach"); removeObjVar( giver, "trainingSkillToLearn"); if( skill_id == learn_skill) { if( 0x00) { bark( this, "And we agree on what to learn."); } int skill_diff; int has_gold = getResource( skill_diff, givenobj, "gold", 0x03, 0x02); if( 0x00) { string debug_str = skill_diff; bark( this, debug_str); if( ! has_gold) { bark( this, "Failed to get gold resource on item."); } } if( ! has_gold) { bark( this, "I require gold in payment!"); return( 0x00); } if( skill_diff < 0x0A) { bark( this, "'Tis but a pittance! I require 10 gold at a minimum."); return( 0x00); } skill_diff = skill_diff / 0x0A; if( skill_diff > 0x00) { if( 0x00) { bark( this, "And I was paid."); } if( skill_diff > getSkillLevel( this, skill_id)) { if( 0x00) { bark( this, "Overpaid, even."); } skill_diff = getSkillLevel( this, skill_id) - getSkillLevel( giver, skill_id); } addSkillLevel( giver, skill_id, skill_diff); bark( this, "Let me show thee something of how this is done."); begin_convo_pause( this); if( ( isShopkeeper( this)) && ( getObjType( givenobj) == 0x0EED)) { int deposit_ok = depositIntoBank( this, givenobj, skill_diff); } else { if( ! putObjContainer( givenobj, this)) { if( teleport( givenobj, getLocation( this))) { bark( this, "A pity, I lack the hands to carry the gold!"); } else { bark( this, "Here, thou mayst as well keep thy gold."); } } } systemMessage( giver, "Your skill level increases."); intRet( 0x01); return( 0x00); } } } } list item_resources; int magic_lvl; int i; int j; int result; int is_wanted; list npc_food_res; list npc_desire_res; list spare_list; string npc_food_key; string npc_desire_key; string spare_str; string item_res_key; string item_name; int is_food; item_name = getName( givenobj); if( getResourcesOnObj( givenobj, 0x03, item_resources)) { if( getResourcesOnObj( this, 0x00, npc_food_res)) { for( i = 0x00; i < numInList( npc_food_res); i ++) { for( j = 0x00; j < numInList( item_resources); j ++) { npc_food_key = npc_food_res [ i ]; item_res_key = item_resources [ j ]; if( npc_food_key == item_res_key) { is_food = 0x01; is_wanted = 0x01; if( 0x00) { bark( this, "Found a food match."); } item_name = getResourceName( npc_food_key, 0x00); } } } } if( getResourcesOnObj( this, 0x02, npc_desire_res)) { for( i = 0x00; i < numInList( npc_desire_res); i ++) { for( j = 0x00; j < numInList( item_resources); j ++) { npc_desire_key = npc_desire_res [ i ]; item_res_key = item_resources [ j ]; if( npc_desire_key == item_res_key) { setDesireLevel( this, 0x64); if( 0x00) { bark( this, "Found a desire match."); } is_wanted = 0x01; item_name = getResourceName( npc_desire_key, 0x02); } } } } string msg; msg = "Thou art giving me " + item_name + "?"; bark( this, msg); begin_convo_pause( this); obj gift_obj; int gold_amt2; int ok; if( is_wanted) { if( getObjType( givenobj) == 0x0EED) { string gold_msg; ok = getResource( gold_amt2, givenobj, "gold", 0x03, 0x02); if( gold_amt2 > 0xFA) { gold_msg = "'Tis a noble gift."; } else { gold_msg = "Money is always welcome."; } bark( this, gold_msg); } begin_convo_pause( this); if( 0x00) { bark( this, "Accepting item."); } if( isShopkeeper( this)) { if( getObjType( givenobj) == 0x0EED) { ok = getResource( gold_amt2, givenobj, "gold", 0x03, 0x02); ok = depositIntoBank( this, givenobj, gold_amt2); intRet( 0x01); return( 0x01); } else { result = putObjContainer( givenobj, this); if( ! result) { result = teleport( givenobj, getLocation( this)); bark( this, "Oops, I dropped it."); } } } else { result = putObjContainer( givenobj, this); if( ! result) { result = teleport( givenobj, getLocation( this)); bark( this, "Oops, I dropped it."); } } if( is_food) { bark( this, "This tasteth good."); list eat_sfx = 0x3C, 0x3B, 0x3A; sfx( getLocation( this), eat_sfx [ random( 0x00, 0x02) ], 0x00); } list contents; obj item; obj best_magic_item; int best_magic_lvl = 0x00; list item_res; getContents( contents, this); for( i = 0x00; i < numInList( contents); i ++) { item = contents [ i ]; if( getResourcesOnObj( item, 0x03, item_res)) { magic_lvl = 0x00; result = getResource( magic_lvl, item, "magic", 0x03, 0x02); if( magic_lvl > best_magic_lvl) { best_magic_lvl = magic_lvl; best_magic_item = item; } } } list containers; getContainersOnMobile( containers, this); for( i = 0x00; i < numInList( containers); i ++) { item = containers [ i ]; getContents( contents, item); for( j = 0x00; j < numInList( contents); j ++) { item = contents [ j ]; if( getResourcesOnObj( item, 0x03, item_res)) { magic_lvl = 0x00; result = getResource( magic_lvl, item, "magic", 0x03, 0x02); if( magic_lvl > best_magic_lvl) { best_magic_lvl = magic_lvl; best_magic_item = item; } } } } gift_obj = best_magic_item; if( gift_obj == NULL( )) { if( hasObjVar( this, "ScavengeLastItemGotten")) { obj last_item = getObjVar( this, "ScavengeLastItemGotten"); if( hasObj( this, last_item)) { gift_obj = last_item; } } } if( gift_obj == NULL( )) { i = getValue( givenobj); if( getObjType( givenobj) == 0x0EED) { i = 0x00; } if( getObjType( givenobj) == 0x0EEE) { i = 0x00; } if( getObjType( givenobj) == 0x0EEF) { i = 0x00; } if( i) { gift_obj = transferGenericToContainer( this, this, 0x0EED, i); if( gift_obj != NULL( )) { sfx( getLocation( giver), 0x35, 0x00); } } } if( getNotoriety( this) > 0x00) { addNotoriety( giver, 0x05); } else { removeNotoriety( giver, 0x05); } update_fame_memory( this, giver, 0x32); if( hasObjVar( this, "myBoss")) { list boss_list; getObjListVar( boss_list, this, "myBoss"); if( ! isInList( boss_list, giver)) { stopFollowing( this); } } setDesireLevel( this, 0xC8); if( gift_obj == NULL( )) { bark( this, "I thank thee."); bark( this, get_rumor( this, giver)); intRet( 0x01); return( 0x00); } replyTo( this, giver, "@InternalAcceptItem"); msg = "Please accept "; i = getObjType( gift_obj); msg = msg + getArticle( i); msg = msg + " "; msg = msg + getName( gift_obj); msg = msg + "."; if( giveItem( giver, gift_obj) == NULL( )) { i = teleport( gift_obj, getLocation( giver)); } bark( this, msg); intRet( 0x01); return( 0x00); } } setObjVar( this, "theItemGiven", item_name); if( 0x00) { bark( this, "Refusing item."); } bark( this, "I am not interested in this."); replyTo( this, giver, "@InternalRefuseItem"); if( giveItem( giver, givenobj) == NULL( )) { bark( this, "Thy hands are full, so here 'tis, on the ground."); i = teleport( givenobj, getLocation( giver)); } begin_convo_pause( this); return( 0x00);
}

old_human.@convofunc(\"GetItem\").source:
trigger convofunc("GetItem") {
  string theItemGiven; if( hasObjVar( this, "theItemGiven")) { theItemGiven = getObjVar( this, "theItemGiven"); removeObjVar( this, "theItemGiven"); } else { theItemGiven = "item"; } setConvoRet( theItemGiven); return( 0x00);
}

old_human.@gotattacked.source:
trigger gotattacked {
  update_fame_memory( this, attacker, 0x4B); return( 0x01);
}

openflour.@use.source:
trigger use {
  if( isAtHome( this)) { systemMessage( user, "That flour belongs to someone else."); return( 0x00); } if( hasObjVar( this, "inUse")) { systemMessage( user, "Someone is using that flour."); return( 0x00); } else { setObjVar( this, "inUse", 0x01); callback( this, 0x1E, 0x1B); } barkTo( this, user, "Mix the flour with water to make dough"); targetObj( user, this); return( 0x00);
}

openflour.@targetobj.source:
trigger targetobj {
  if( usedon == NULL( )) { if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } return( 0x00); } int rc; int water_amt; int used_type = getObjType( usedon); loc location = getLocation( usedon); obj backpack = getBackpack( user); obj dough; if( hasObjVar( usedon, "drinkType")) { string drinkType; drinkType = getObjVar( usedon, "drinkType"); if( drinkType == "water") { returnResourcesToBank( usedon, 0x01, "water"); returnResourcesToBank( this, 0x01, "flour"); dough = createNoResObjectIn( 0x103D, backpack); systemMessage( user, "You make some dough and put it in your backpack"); } rc = getResource( water_amt, usedon, "water", 0x03, 0x02); if( water_amt < 0x01) { if( hasObjVar( usedon, "emptyVersion")) { removeObjVar( usedon, "drinkType"); int emptyVersion = getObjVar( usedon, "emptyVersion"); setType( usedon, emptyVersion); } else { deleteObject( usedon); } } } else { switch( used_type) { case 0x103D string name; name = getObjVar( usedon, "NAME"); if( name == "sweet dough") { setType( usedon, 0x103F); attachScript( usedon, "4159"); removeObjVar( usedon, "NAME"); setObjVar( usedon, "NAME", "cake mix"); detachScript( usedon, "4157"); } break; case 0x0FFA case 0x154D case 0x0E7B rc = getResource( water_amt, usedon, "water", 0x03, 0x02); if( water_amt > 0x00) { returnResourcesToBank( usedon, 0x01, "water"); } rc = getResource( water_amt, usedon, "water", 0x03, 0x02); if( water_amt < 0x01) { if( used_type == 0x0FFA) { change_type( usedon, 0x14E0); } if( used_type == 0x154D) { change_type( usedon, 0x0E77); } if( used_type == 0x0E7B) { change_type( usedon, 0x0E83); } } returnResourcesToBank( this, 0x01, "flour"); dough = createNoResObjectIn( 0x103D, backpack); systemMessage( user, "You make some dough and put it in your backpack"); break; case 0x15F8 setType( usedon, 0x0A1E); attachScript( usedon, "2590"); transferResources( usedon, this, 0x01, "flour"); break; default systemMessage( user, "Can't use flour on that."); break; } } int flour_amt; rc = getResource( flour_amt, this, "flour", 0x03, 0x02); if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } if( flour_amt < 0x01) { int this_type = getObjType( this); if( this_type == 0x0A1E) { setType( this, 0x15F8); detachScript( this, "2590"); return( 0x01); } else { deleteObject( this); } } return( 0x00);
}

openflour.@callback(0x1B).source:
trigger callback(0x1B) {
  if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } return( 0x01);
}

opengate.prompt_moongate_confirm.source:
function void prompt_moongate_confirm(obj me, obj player) {
  list options; appendToList( options, 0x00); appendToList( options, "Yes"); appendToList( options, 0x01); appendToList( options, "No"); selectType( player, me, 0x2C, "Dost thou wish to step into the moongate?", options); return( );
}

opengate.teleport_player_to_dest.source:
function int teleport_player_to_dest(obj me, obj player) {
  teleport_followers( player, dest_loc); if( teleport( player, dest_loc)) { sfx( getLocation( player), 0x01FE, 0x00); return( 0x01); } return( 0x00);
}

opengate.is_justice_exit.source:
function int is_justice_exit(obj me, obj player) {
  if( ( inJusticeRegion( getLocation( me))) && ( ! inJusticeRegion( dest_loc))) { return( 0x01); } return( 0x00);
}

opengate.can_enter_gate.source:
function int can_enter_gate(obj gate, obj it) {
  if( ! is_active) { return( 0x00); } if( getDistanceInTiles( getLocation( gate), getLocation( it)) > 0x01) { return( 0x00); } int it_z = getZ( getLocation( it)); int gate_z = getZ( getLocation( gate)); int gate_height = getHeight( gate); int gate_top = gate_z + gate_height; if( ( it_z < gate_z) || ( it_z > gate_top)) { return( 0x00); } return( 0x01);
}

opengate.handle_gate_enter.source:
function int handle_gate_enter(obj gate, obj player) {
  if( ! can_enter_gate( gate, player)) { return( 0x01); } reveal_and_notify( player); int result; if( is_justice_exit( gate, player)) { prompt_moongate_confirm( gate, player); result = teleport( player, getLocation( gate)); return( 0x00); } else { result = teleport_player_to_dest( gate, player); } return( 0x00);
}

opengate.@creation.source:
trigger creation {
  setX( dest_loc, getObjVar( this, "xPoint")); setY( dest_loc, getObjVar( this, "yPoint")); setZ( dest_loc, getObjVar( this, "zPoint")); return( 0x00);
}

opengate.@enterrange(0x00).source:
trigger enterrange(0x00) {
  return( handle_gate_enter( this, target));
}

opengate.@use.source:
trigger use {
  if( getLocation( this) == getLocation( user)) { int result = handle_gate_enter( this, user); } return( 0x00);
}

opengate.@typeselected(0x2C).source:
trigger typeselected(0x2C) {
  if( listindex == 0x00) { return( 0x00); } if( objtype != 0x00) { return( 0x00); } if( ! can_enter_gate( this, user)) { return( 0x00); } int result = teleport_player_to_dest( this, user); return( 0x00);
}

opengate.@callback(0x79).source:
trigger callback(0x79) {
  loc gate_loc = getLocation( this); int okay = 0x01; if( ! hasObjVar( this, "sourceGate")) { deleteObject( this); } if( isAnyMultiAt( gate_loc) != NULL( )) { okay = 0x00; } if( has_gate_at_loc( gate_loc, this)) { okay = 0x00; } list status_args; appendToList( status_args, okay); obj source_gate = getObjVar( this, "sourceGate"); appendToList( status_args, this); multimessage( source_gate, "gatestatus", status_args); is_active = okay; if( ! okay) { deleteObject( this); } return( 0x01);
}

opengate.@message(\"gatestatus\").source:
trigger message("gatestatus") {
  int i = args [ 0x00 ]; if( i) { is_active = 0x01; } else { deleteObject( this); } return( 0x01);
}

oracle.addMessage.source:
function void addMessage(list msg) {
  list messages; getObjListVar( messages, this, "oracleMessages"); appendToList( messages, msg); setObjVar( this, "oracleMessages", messages); bark( this, "Message added."); return( );
}

oracle.show_messages.source:
function void show_messages() {
  list messages; getObjListVar( messages, this, "oracleMessages"); if( numInList( messages) < 0x01) { bark( this, "No messages are set."); return( ); } string keyword; string t; list entry; for( int i = 0x00; i < numInList( messages); i ++) { copyList( entry, messages [ i ]); keyword = entry [ 0x00 ]; t = entry [ 0x01 ]; bark( this, "'" + t + "', Keyword: '" + keyword + "'.'"); } return( );
}

oracle.find_message_index.source:
function int find_message_index(string keyword) {
  int idx; list a; getObjListVar( a, this, "oracleMessages"); list entry; string stored_keyword; for( int i = 0x00; i < numInList( a); i ++) { copyList( entry, a [ i ]); stored_keyword = entry [ 0x00 ]; if( keyword == stored_keyword) { return( idx); } } return( 0x00 - 0x01);
}

oracle.match_keyword_index.source:
function int match_keyword_index(list w) {
  list a; getObjListVar( a, this, "oracleMessages"); string keyword; string word; list entry; for( int i = 0x00; i < numInList( w); i ++) { word = w [ i ]; for( int j = 0x00; j < numInList( a); j ++) { copyList( entry, a [ j ]); keyword = entry [ 0x00 ]; if( keyword == word) { return( j); } } } return( 0xFF);
}

oracle.get_message_text.source:
function string get_message_text(int idx) {
  list entry; list a; getObjListVar( a, this, "oracleMessages"); copyList( entry, a [ idx ]); string text = entry [ 0x01 ]; return( text);
}

oracle.@creation.source:
trigger creation {
  list messages; setObjVar( this, "oracleMessages", messages); return( 0x00);
}

oracle.@textentry(0x22).source:
trigger textentry(0x22) {
  pending_message_text = text; bark( this, "Adding text '" + pending_message_text + "'."); systemMessage( sender, "Enter the keyword that will trigger this response."); textEntry( this, sender, 0x24, 0x00, ""); return( 0x00);
}

oracle.@textentry(0x24).source:
trigger textentry(0x24) {
  list u = text, pending_message_text; addMessage( u); return( 0x00);
}

oracle.@textentry(0x23).source:
trigger textentry(0x23) {
  int idx = find_message_index( text); if( idx == ( 0x00 - 0x01)) { systemMessage( sender, "That keyword was not found."); return( 0x00); } list a; getObjListVar( a, this, "oracleMessages"); removeItem( a, idx); systemMessage( sender, "Oracle string removed."); setObjVar( this, "oracleMessages", a); return( 0x00);
}

oracle.@use.source:
trigger use {
  int can_edit = 0x00; if( hasObjVar( user, "allowedToEditOracle")) { can_edit = 0x01; } if( isEditing( user)) { can_edit = 0x01; } if( ! can_edit) { return( 0x01); } list menu; appendToList( menu, 0x00); appendToList( menu, "View conversation strings."); appendToList( menu, 0x01); appendToList( menu, "Add a conversation string."); appendToList( menu, 0x02); appendToList( menu, "Remove a conversation string."); appendToList( menu, 0x03); appendToList( menu, "Clear all conversation strings."); selectType( user, this, 0x3A, "ORACLE CONTROL MENU", menu); return( 0x00);
}

oracle.@typeselected(0x3A).source:
trigger typeselected(0x3A) {
  if( listindex == 0x00) { return( 0x00); } switch( objtype) { case 0x00 show_messages( ); break; case 0x01 systemMessage( user, "Enter the text of the oracle message:"); textEntry( this, user, 0x22, 0x00, ""); break; case 0x02 systemMessage( user, "Enter the keyword of the message to remove:"); textEntry( this, user, 0x23, 0x00, ""); break; case 0x03 list empty_list; setObjVar( this, "oracleMessages", empty_list); systemMessage( user, "All oracle messages cleared."); break; default return( 0x00); break; } return( 0x00);
}

oracle.@speech(\"*\").source:
trigger speech("*") {
  if( getDistanceInTiles( getLocation( this), getLocation( speaker)) > 0x04) { return( 0x01); } list words; split( words, arg); int msg_index = match_keyword_index( words); if( msg_index != 0xFF) { bark( this, get_message_text( msg_index)); return( 0x00); } return( 0x01);
}

orderchaos.has_order_shield.source:
function int has_order_shield(obj mobile) {
  if( hasObjType( mobile, 0x1BC3) || hasObjTypeInBank( mobile, 0x1BC3)) { return( 0x01); } return( 0x00);
}

orderchaos.has_chaos_shield.source:
function int has_chaos_shield(obj mobile) {
  if( hasObjType( mobile, 0x1BC4) || hasObjTypeInBank( mobile, 0x1BC4) || hasObjType( mobile, 0x1BC5) || hasObjTypeInBank( mobile, 0x1BC5)) { return( 0x01); } return( 0x00);
}

orderchaos.has_faction_sigil.source:
function int has_faction_sigil(obj player) {
  if( is_order_faction) { return( has_order_shield( player)); } return( has_chaos_shield( player));
}

orderchaos.has_rival_sigil.source:
function int has_rival_sigil(obj player) {
  if( is_order_faction) { return( has_chaos_shield( player)); } return( has_order_shield( player));
}

orderchaos.handle_virtue_guard_speech.source:
function int handle_virtue_guard_speech(obj speaker, obj this) {
  list responses; string response; if( has_faction_sigil( speaker)) { responses = "Hail and well met!", "Greetings, fellow guard.", "In the name of our liege, greetings!", "Greetings, my friend.", "Hail, my friend.", "Yes, thou'rt a virtue guard.", "Hmm? Yes, I am one. So art thou.", "Yes, as thou knowest, it is a great thing to be one!", "Isn't it wonderful being a virtue guard?", "Why dost thou ask about virtue guards when thou art one?"; response = responses [ random( 0x00, numInList( responses) - 0x01) ]; bark( this, response); return( 0x00); } if( has_rival_sigil( speaker)) { responses = "Stay away, lest our rivalry develop into something worse!", "Thou'rt not of my brotherhood! Away with thee!", "Whilst I grant respect to thy lord, I mislike thy emblem.", "Art thou here to harass me?", "Tch tch... thou wearest the wrong emblem!", "'Tis a pity that thou art in the wrong camp!", "There is a rivalry between thy group and mine--be careful.", "Is not thy emblem a sign that thou art a member of our rival guards?"; response = responses [ random( 0x00, numInList( responses) - 0x01) ]; bark( this, response); return( 0x00); } if( getNotoriety( speaker) < 0x7F) { responses = "Thou art not worthy of being a member of our fraternity.", "The guards will not accept thee until thy reputation improves.", "Thou hast not the unblemished record we expect from our members.", "Thy record is not good enough to join the guards.", "Only those of utmost probity are accepted into the guards.", "Only the very best of citizens may join the guards.", "Thou dost not qualify for the virtue guards; thy record is not good enough."; response = responses [ random( 0x00, numInList( responses) - 0x01) ]; if( getNotorietyLevel( speaker) > 0x04) { response = response + " Thou'rt extremely close, however."; } else { if( getNotorietyLevel( speaker) < 0x00) { response = response + " Do not dishonor us by asking again, scum."; } } bark( this, response); return( 0x00); } if( is_order_faction) { responses