  if( usedon == NULL( )) { return( 0x00); } if( ! canSeeObj( user, usedon)) { systemMessage( user, "Target can not be seen."); return( 0x00); } if( hasScript( usedon, "beingtamed")) { ebarkTo( usedon, user, "Someone else is already taming this."); return( 0x00); } if( hasObjListVar( usedon, "myBoss")) { ebarkTo( usedon, user, "That animal looks tame already."); return( 0x00); } if( isMobile( usedon)) { if( ! hasObjVar( usedon, "petCanTame")) { ebarkTo( usedon, user, "That being can not be tamed."); } int tame_difficulty = getObjVar( usedon, "petCanTame"); int success = testAndLearnSkill( user, 0x14, 0x08 * tame_difficulty, 0x32); if( success >= 0x03E8) { ebarkTo( usedon, user, "That wasn't even challenging."); } if( success < 0x00) { systemMessage( user, "You don't seem to be able to persuade that to move."); return( 0x00); } if( animal_selected) { if( usedon == user) { systemMessage( user, "The animal begins to follow you."); animal_selected = 0x00; followNpc( animal, usedon, 0x00); } } else { if( ! isHuman( usedon) && ( hasObjVar( usedon, "petCanTame"))) { animal_selected = 0x01; animal = usedon; targetLoc( user, this); systemMessage( user, "Click whom you wish the animal to follow, or where you wish it to go."); return( 0x00); break; } systemMessage( user, "That is not a herdable animal."); } } return( 0x00);
