function int create_ship_key(obj deed, obj user, obj ship, int bank) {
  loc user_loc = getLocation( user); list key_types = 0x100E, 0x100F, 0x1010, 0x1013; int num = random( 0x00, ( numInList( key_types) - 0x01)); int key_type = key_types [ num ]; obj container = NULL( ); if( bank) { fixBank( user); container = getItemAtSlot( user, 0x1D); if( container == NULL( )) { container = getBackpack( user); bank = 0x00; } } else { container = getBackpack( user); } obj key = NULL( ); if( container == NULL( )) { key = createGlobalObjectAt( key_type, user_loc); barkTo( user, user, "A ship's key is now at my feet."); } else { key = createGlobalObjectIn( key_type, container); if( bank) { barkTo( user, user, "A ship's key is now in my safety deposit box."); } else { barkTo( user, user, "A ship's key is now in my backpack."); } } if( key == NULL( )) { barkTo( user, user, "Ack, a key could not be created!"); return( 0x00); } attachScript( key, "key"); attachScript( key, "shipkey"); list doors; if( hasObjVar( ship, "myhousedoors")) { getObjListVar( doors, ship, "myhousedoors"); } obj door; int num_doors = numInList( doors); for( int i = 0x00; i < num_doors; i ++) { door = doors [ i ]; attach_lockable_to_key( door, key); } return( 0x01);
}

