shipstuff.check_move_steps.source:
function int check_move_steps(obj ship, int dir, int steps) {
  loc location; int result; location = getLocation( ship); for( int i = steps; i > 0x00; i --) { moveDir( location, dir); } result = moveMultiCheck( ship, location, multi_check_flags); if( result <= 0x00) { int reverse_dir = ( dir + 0x04) % 0x08; while( ( result <= 0x00) && ( steps > 0x01)) { steps --; moveDir( location, reverse_dir); result = moveMultiCheck( ship, location, multi_check_flags); } } return( result);
}

