function int move_ship_or_map_switch(obj ship, int direction_offset, obj tillerman) {
  int direction = resolve_move_dir( ship, direction_offset); int multi_type = getMultiType( ship); loc min_bounds; loc max_bounds; int extents_result = getMultiExtents( multi_type, min_bounds, max_bounds); int width = getX( max_bounds) - getX( min_bounds) + 0x01; int height = getY( max_bounds) - getY( min_bounds) + 0x01; loc dest = getLocation( ship); int x_steps = 0x00; int y_steps = 0x00; switch( direction) { case 0x00 case 0x04 y_steps = height; break; case 0x01 case 0x03 case 0x05 case 0x07 x_steps = width; y_steps = height; break; case 0x02 case 0x06 x_steps = width; break; default x_steps = width; y_steps = height; break; } int x_dir = 0x00; int y_dir = 0x00; switch( direction) { case 0x00 y_dir = 0x00; break; case 0x01 x_dir = 0x02; y_dir = 0x00; break; case 0x02 x_dir = 0x02; break; case 0x03 x_dir = 0x02; y_dir = 0x04; break; case 0x04 y_dir = 0x04; break; case 0x05 x_dir = 0x06; y_dir = 0x04; break; case 0x06 x_dir = 0x06; break; case 0x07 x_dir = 0x06; y_dir = 0x00; break; default break; } for( ; x_steps > 0x00; x_steps --) { moveDir( dest, x_dir); } for( ; y_steps > 0x00; y_steps --) { moveDir( dest, y_dir); } if( isInMap( dest)) { if( hasObjVar( tillerman, "oldshipcommand")) { removeObjVar( tillerman, "oldshipcommand"); } int move_result = moveMultiCheck( ship, dest, multi_check_flags); did_normal_move = 0x01; return( move_result); } attach_naked_hack_to_crew( ship); return( moveMultiMapSwitch( ship, dest, multi_check_flags));
}

