shiptillerman.nav_to_waypoint.source:
function int nav_to_waypoint(obj tillerman, int single_step) {
  string msg; string num_str; obj ship = getMultiSlaveId( tillerman); if( ship == NULL( )) { bark( tillerman, "Blimey, I have no ship!"); return( 0x00); } if( ( ! isValid( nav_map)) || ( ! isMap( nav_map))) { bark( tillerman, "I have seen no map, sir."); nav_map = NULL( ); return( 0x00); } if( getDistanceInTiles( getLocation( nav_map), getLocation( tillerman)) > 0x0F) { bark( tillerman, "The map is too far away from me, sir."); nav_map = NULL( ); return( 0x00); } loc nav_loc; if( ! getMapPoint( nav_loc, nav_map, nav_point_index)) { msg = "Nav point "; num_str = nav_point_index + 0x01; concat( msg, num_str); concat( msg, " is invalid, sir."); bark( tillerman, msg); nav_point_index = ( 0x00 - 0x01); return( 0x00); } loc ship_loc = getLocation( ship); if( getDistanceInTiles( ship_loc, nav_loc) <= ship_max_dimension) { if( single_step) { msg = "We have arrived at nav "; num_str = nav_point_index + 0x01; concat( msg, num_str); concat( msg, ", sir."); bark( tillerman, msg); nav_point_index ++; int cleared_cmd = pop_ship_command( tillerman); return( 0x00); } nav_point_index ++; if( ! getMapPoint( nav_loc, nav_map, nav_point_index)) { nav_point_index = ( 0x00 - 0x01); bark( tillerman, "The course is completed, sir."); cleared_cmd = pop_ship_command( tillerman); return( 0x00); } msg = "Heading to nav point "; num_str = nav_point_index + 0x01; concat( msg, num_str); concat( msg, ", sir."); bark( tillerman, msg); } int target_dir = getDirectionInternal( ship_loc, nav_loc); int ship_dir = getObjVar( ship, "myshipdir"); ship_dir = ship_dir * 0x02; int dir_diff = get_direction_delta( target_dir, ship_dir); int command = 0x00; if( ( dir_diff > 0x01) || ( dir_diff < ( 0x00 - 0x01))) { if( dir_diff < 0x00) { command = 0x09; } else { command = 0x08; } } else { if( dir_diff == 0x01) { command = 0x01; } else { if( dir_diff == ( 0x00 - 0x01)) { command = 0x07; } else { command = 0x00; } } } return( exec_ship_command( tillerman, command, 0x01));
}

