function int exec_ship_command(obj tillerman, int cmd, int continuous) {
  int result; obj ship = getMultiSlaveId( this); if( ship == NULL( )) { int cleared_cmd = pop_ship_command( tillerman); bark( this, "Ar, I have no ship!"); return( 0x00); } if( anchor_down == 0x01) { bark( this, "Ar, the anchor is down sir!"); return( 0x00); } if( ( cmd >= 0x08) && ( cmd <= 0x0A)) { int rotation_type = cmd - 0x07; result = rotate_ship_delta( ship, rotation_type); if( result > 0x00) { if( ! continuous) { bark( tillerman, "Yes, sir."); } } else { if( result < 0x00) { bark( tillerman, "Arr, the water is too turbulent to turn sir!"); } else { bark( tillerman, "Ar, can't turn sir."); } cleared_cmd = pop_ship_command( tillerman); return( 0x00); } if( ! continuous) { cleared_cmd = pop_ship_command( tillerman); return( 0x00); } return( 0x01); } if( ( ( cmd >= 0x00) && ( cmd <= 0x07)) || ( ( cmd >= 0x0B) && ( cmd <= 0x1A)) || ( ( cmd >= 0x1D) && ( cmd <= 0x24))) { int speed = 0x01; int dir = 0x00; if( ( cmd >= 0x00) && ( cmd <= 0x07)) { dir = cmd; if( ( cmd == 0x00) || ( cmd == 0x01) || ( cmd == 0x07)) { speed = 0x03; } } if( ( cmd >= 0x0B) && ( cmd <= 0x12)) { dir = cmd - 0x0B; } if( ( cmd >= 0x13) && ( cmd <= 0x1A)) { dir = cmd - 0x13; if( ( dir == 0x00) || ( dir == 0x01) || ( dir == 0x07)) { speed = 0x03; } } if( ( cmd >= 0x1D) && ( cmd <= 0x24)) { dir = cmd - 0x1D; } result = move_ship_relative( ship, dir, speed); if( result == 0x00) { bark( tillerman, "Ar, we've stopped sir.") cleared_cmd = pop_ship_command( tillerman); clear_queued_command( tillerman); return( 0x00); } else { if( result < 0x00) { bark( tillerman, "Ar, turbulent water!") save_ship_command( tillerman); result = move_ship_or_map_switch( ship, dir, tillerman); if( ! continuous) { if( ! did_normal_move) { cleared_cmd = pop_ship_command( tillerman); } else { did_normal_move = 0x00; } } return( 0x00); } else { if( ( ( cmd >= 0x13) && ( cmd <= 0x1A)) || ( ( cmd >= 0x1D) && ( cmd <= 0x24))) { if( ! continuous) { cleared_cmd = pop_ship_command( tillerman); } } } } return( 0x01); } if( cmd == 0x1B) { return( nav_to_waypoint( tillerman, 0x00)); } if( cmd == 0x1C) { return( nav_to_waypoint( tillerman, 0x01)); } if( cmd >= 0x25) { bark( this, "Ar, I don't know how to do that, sir."); cleared_cmd = pop_ship_command( tillerman); return( 0x00); } return( 0x00);
}

