shiptillerman.@speech(\"*\").source:
trigger speech("*") {
  if( containedBy( this) != NULL( )) { return( 0x01); } obj ship = getMultiSlaveId( this); if( isDead( speaker) && ( ! isManifesting( speaker))) { return( 0x01); } if( ! isOnMulti( speaker, ship)) { return( 0x01); } if( ( ! has_ship_key( ship, speaker)) && ( ! isEditing( speaker))) { obj closest_player = getClosestVisibleOnlinePlayer( getLocation( this), 0x0F); if( ( closest_player == NULL( )) || ( ( closest_player != speaker))) { return( 0x01); } list players; getPlayersOnMulti( players, ship); int count = numInList( players); int i; for( i = 0x00; i < count; i ++) { obj player = players [ i ]; if( has_ship_key( ship, player)) { return( 0x01); } } } list args; split( args, arg); string msg; string word1; string word2; string word3; int num = numInList( args); if( num > 0x02) { word1 = args [ 0x00 ]; word2 = args [ 0x01 ]; if( ( word1 == "set") && ( word2 == "name")) { string ship_name; string word; for( int j = 0x02; j < num; j ++) { if( j != 0x02) { concat( ship_name, " "); } word = args [ j ]; concat( ship_name, word); } msg = "This ship is now called the "; concat( msg, ship_name); concat( msg, "."); set_name( ship, ship_name); barkTo( this, speaker, msg); return( 0x01); } } if( num == 0x01) { word1 = args [ 0x00 ]; if( word1 == "name") { if( has_name( ship)) { msg = "This is the "; concat( msg, get_custom_multi_name( ship)); concat( msg, "."); bark( this, msg); } else { bark( this, "Ar, this ship has no name."); } return( 0x01); } if( word1 == "forward") { set_ship_command( this, 0x00); bark( this, "Aye aye sir."); return( 0x01); } if( ( word1 == "backwards") || ( word1 == "backward") || ( word1 == "back")) { set_ship_command( this, 0x04); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "left") { set_ship_command( this, 0x06); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "right") { set_ship_command( this, 0x02); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "stop") { int prev_cmd = pop_ship_command( this); bark( this, "Yes,