word2 == "left")) { set_ship_command( this, 0x07); bark( this, "Aye aye sir."); return( 0x01); } if( ( word1 == "forward") && ( word2 == "right")) { set_ship_command( this, 0x01); bark( this, "Aye aye sir."); return( 0x01); } if( ( ( word1 == "backward") && ( word2 == "left")) || ( ( word1 == "backwards") && ( word2 == "left")) || ( ( word1 == "back") && ( word2 == "left"))) { set_ship_command( this, 0x05); bark( this, "Aye aye sir."); return( 0x01); } if( ( ( word1 == "backward") && ( word2 == "right")) || ( ( word1 == "backwards") && ( word2 == "right")) || ( ( word1 == "back") && ( word2 == "right"))) { set_ship_command( this, 0x03); bark( this, "Aye aye sir."); return( 0x01); } if( ( word1 == "turn") && ( word2 == "right")) { set_ship_command( this, 0x08); return( 0x01); } if( ( word1 == "turn") && ( word2 == "left")) { set_ship_command( this, 0x09); return( 0x01); } if( ( word1 == "turn") && ( word2 == "around")) { set_ship_command( this, 0x0A); return( 0x01); } if( ( word1 == "come") && ( word2 == "about")) { set_ship_command( this, 0x0A); return( 0x01); } if( ( word1 == "drift") && ( word2 == "left")) { set_ship_command( this, 0x06); bark( this, "Aye aye sir."); return( 0x01); } if( ( word1 == "drift") && ( word2 == "right")) { set_ship_command( this, 0x02); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "slow") { if( word2 == "left") { set_ship_command( this, 0x11); bark( this, "Aye aye sir."); return( 0x01); } if( word2 == "right") { set_ship_command( this, 0x0D); bark( this, "Aye aye sir."); return( 0x01); } if( word2 == "forward") { set_ship_command( this, 0x0B); bark( this, "Aye aye sir."); return( 0x01); } if( ( word2 == "back") || ( word2 == "backward") || ( word2 == "backwards")) { set_ship_command( this, 0x0F); bark( this, "Aye aye sir."); return( 0x01); } } if( word1 == "one") { if( word2 == "left") { set_ship_command( this, 0x23); bark( this, "Aye aye sir."); return( 0x01); } if( word2 == "right") { set_ship_command( this, 0x1F); bark( this, "Aye aye sir."); return( 0x01); } if( word2 == "forward") { set_ship_command( this, 0x1D); bark( this, "Aye aye sir."); return( 0x01); } if( ( word2 == "back") || ( word2 == "backward") || ( word2 == "backwards")) { set_ship_command( this, 0x21); bark( this, "Aye aye sir."); return( 0x01); } } if( word2 == "one") { if( word1 == "left") { set_ship_command( this, 0x23); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "right") { set_ship_command( this, 0x1F); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "forward") { set_ship_command( this, 0x1D); bark( this, "Aye aye sir."); return( 0x01); } if( ( word1 == "back") || ( word1 == "backward") || ( word1 == "backwards")) { set_ship_command( this, 0x21); bark( this, "Aye aye sir."); return( 0x01); } } if( word1 == "goto") { set_nav_point( strtoi( word2) - 0x01); set_ship_command( this, 0x1B); bark( this, "Aye aye sir."); return( 0x01); } if( word1 == "single") { set_nav_point( strtoi( word2) - 0x01); set_ship_command( this, 0x1C); bark( this, "Aye aye sir."); return( 0x01); } return( 0x01); } if( num == 0x03) { word1 = args [ 0x00 ]; word2 = args [ 0x01 ]; word3 = args [ 0x02 ]; if( word1 == "slow") { if( word2 == "forward") { if( word3 == "left") { set_ship_command( this, 0x12); bark( this, "Aye aye sir."); return( 0x01); } if( word3 == "right") { set_ship_command( this, 0x0C); bark( this, "Aye aye sir."); return( 0x01); } } if( ( word2 == "back") || ( word2 == "backward") || ( word2 == "backwards")) { if( word3 == "left") { set_ship_command( this, 0x10); bark( this, "Aye aye sir."); return( 0x01); } if( word3 == "right") { set_ship_command( this, 0x0E); bark( this, "Aye aye sir."); return( 0x01); } } } if( word1 == "one") { if( word2 == "forward") { if( word3 == "left") { set_ship_command( this, 0x24); bark( this, "Aye aye sir."); return( 0x01); } if( word3 == "right") { set_ship_command( this, 0x1E); bark( this, "Aye aye sir."); return( 0x01); } } if( ( word2 == "back") || ( word2 == "backward") || ( word2 == "backwards")) { if( word3 == "left") { set_ship_command( this, 0x22); bark( this, "Aye aye sir."); return( 0x01); } if( word3 == "right") { set_ship_command( this, 0x20); bark( this, "Aye aye sir."); return( 0x01); } } } if( word3 == "one") { if( word1 == "forward") { if( word2 == "left") { set_ship_command( this, 0x24); bark( this, "Aye aye sir."); return( 0x01); } if( word2 == "right") { set_ship_command( this, 0x1E); bark( this, "Aye aye sir."); return( 0x01); } } if( ( word1 == "back") || ( word1 == "backward") || ( word1 == "backwards")) { if( word2 == "left") { set_ship_command( this, 0x22); bark( this, "Aye aye sir."); return( 0x01); } if( word2 == "right") { set_ship_command( this, 0x20); bark( this, "Aye aye sir."); return( 0x01); } } } } return( 0x01);
}

shiptillerman.@give.source:
trigger give {
  int result; if( isMap( givenobj)) { if( ! isValidMap( givenobj)) { bark( this, "Ar, that is not a map, tis but a blank piece of paper!"); } else { loc map_point; if( ! getMapPoint( map_point, givenobj, 0x00)) { bark( this, "Arrrr, this map has no course on it!"); } else { bark( this, "A map!"); nav_map = givenobj; } } } else { bark( this, "Rrrrr, I don't want that!  Show me a map!"); } return( 0x00);
}

