}

shiptillerman.@lookedat.source:
trigger lookedat {
  obj ship = getMultiSlaveId( this); if( has_name( ship)) { string msg = "the tillerman of the "; concat( msg, get_custom_multi_name( ship)); barkTo( this, looker, msg); bark_decay_status( this, looker, "ship"); return( 0x00); } bark_decay_status( this, looker, "ship"); return( 0x01);
}

shiptillerman.@use.source:
trigger use {
  obj ship = getMultiSlaveId( this); if( has_house_key( ship, user)) { systemMessage( user, "What dost thou wish to name thy ship?"); textEntry( this, user, 0x18, 0x00, ""); } else { string reply; int num = random( 0x00, 0x0F); switch( num) { case 0x00 case 0x01 case 0x02 reply = "Arr, don't do that!"; break; case 0x03 case 0x04 case 0x05 reply = "Arr, leave me alone!"; break; case 0x06 case 0x07 case 0x08 reply = "Arr, watch what thou'rt doing, matey!"; break; case 0x09 case 0x0A reply = "Arr!  Do that again and I'll throw ye overboard!"; break; case 0x0B case 0x0C case 0x0D case 0x0E case 0x0F default reply = "Arr!  Only the owner of the ship may change its name!"; break; } bark( this, reply); } return( 0x00);
}

shiptillerman.@textentry(0x18).source:
trigger textentry(0x18) {
  if( button == 0x00) { return( 0x00); } obj ship = getMultiSlaveId( this); if( has_house_key( ship, sender)) { if( text == "") { if( has_name( ship)) { clear_name( ship); barkTo( this, sender, "This ship now has no name."); } } else { string msg = "This ship is now called the "; concat( msg, text); concat( msg, "."); barkTo( this, sender, msg); set_name( ship, text); } } return( 0x00);
}

shrine.try_resurrect_target.source:
function int try_resurrect_target(obj target, int is_chaos) {
  loc shrine_loc = getLocation( this); int shrine_z = getZ( shrine_loc); loc target_loc = getLocation( target); int target_z = getZ( target_loc); int z_diff = shrine_z - target_z; string z_diff_str = z_diff; if( ( z_diff > 0x0A) || ( z_diff < ( 0x00 - 0x0A))) { return( 0x00); } if( isDead( target)) { if( findGoodZ( target_loc, getZ( target_loc), getZ( target_loc), getHeight( target), 0x01) == ( 0x00 - 0x80)) { return( 0x00); } if( ! is_chaos) { if( ! getCompileFlag( 0x01)) { if( getNotorietyLevel( target) < ( 0x00 - 0x02)) { bark( this, "Thy deeds are those of a scoundrel; thou shalt not be resurrected here."); return( 0x00); } } else { if( isMurderer( target)) { bark( this, "Thy deeds are those of a scoundrel; thou shalt not be resurrected here."); return( 0x00); } } } string prompt; if( is_chaos) { prompt = "It is possible for you to be resurrected here at the Chaos Shrine. Do you wish to try?"; } else { prompt = "It is possible for you to be resurrected at this Shrine to the Virtues. Do you wish to try?"; } offer_resurrect( this, target, 0x01, prompt) return( 0x01); } return( 0x00);
}

shrine.@enterrange(0x01).source:
trigger enterrange(0x01) {
  int resurrected = try_resurrect_target( target, is_chaos_shrine); return( ! resurrected);
}

shrine.@use.source:
trigger use {
  if( hasScript( user, "poisoned")) { cure_poison( user); barkTo( this, user, "Thy poison has been cured."); } return( 0x00); if( isDead( user)) { int resurrected = try_resurrect_target( user, is_chaos_shrine); return( 0x00); } int worthy; if( ! getCompileFlag( 0x01)) { if( is_chaos_shrine) { if( getNotoriety( user) < 0x00) { worthy = 0x01; barkTo( this, user, "Thy efforts for the resistance are rewarded."); } } else { if( getNotoriety( user) >= 0x00) { worthy = 0x01; barkTo( this, user, "Strive to continue on the path of benevolence."); } } } else { if( is_chaos_shrine) { if( getKarmaLevel( user) < 0x00) { worthy = 0x01; barkTo( this, user, "Thy efforts for the resistance are rewarded."); } } else { if( getKarmaLevel( user) >= 0x00) { worthy = 0x01; barkTo( this, user, "Strive to continue on the path of benevolence."); } } } if( worthy) { doMobAnimation( user, 0x376A, 0x0A, 0x0F, 0x00, 0x00); restoreHP( user); } else { if( is_chaos_shrine) { int cur_hp = getCurHP( user); barkTo( this, user, "The weak deserve their fate."); doMobAnimation( user, 0x374A, 0x0A, 0x0F, 0x00, 0x00); setCurHP( user, cur_hp / 0x02 + 0x01); } else { int max_hp = getMaxHP( user); int hp_level = getHPLevel( user); if( hp_level < 0x32) { setCurHP( user, max_hp / 0x02); doMobAnimation( user, 0x376A, 0x0A, 0x0F, 0x00, 0x00); barkTo( this, user, "Do more to help others."); } else { barkTo( this, user, "I can not help thee."); } } } return( 0x01);
}

slimesplit.split_slime.source:
function void split_slime(obj attacker) {
  obj n = createGlobalNPCAtSpecificLoc( 0x0232, getLocation( this)); setHue( n, getHue( this)); int half_hp = getCurHP( this); half_hp = half_hp / 0x02; setCurHP( n, half_hp); setCurHP( this, half_hp); attack( n, attacker); sfx( getLocation( this), random( 0x01C8, 0x01CC), 0x00); bark( n, "*The slime splits when struck!*"); return( );
}

sparkler.launch_firework.source:
function void launch_firework() {
  loc launch_loc = getLocation( this); changeLoc( launch_loc, 0x00, 0x00, 0x0A); dest = launch_loc; changeLoc( dest, random( 0x00 - 0x02, 0x02), random( 0x00 - 0x02, 0x02), 0x20); doMissile_Loc2Loc( launch_loc, dest, 0x36E4, 0x05, 0x00, 0x00); shortCallback( this, 0x03, 0x2F); state = 0x01; return( );
}

sparkler.@use.source:
