function int get_base_floor() {
  magery_difficulty = 0x00; attack_difficulty = 0x00; if( cur_mana < 0x4E) { magery_difficulty ++; } if( cur_mana < 0x1A) { magery_difficulty ++; } if( cur_mana < 0x10) { magery_difficulty ++; } if( cur_mana < 0x0A) { magery_difficulty ++; } if( cur_mana < 0x06) { magery_difficulty ++; } if( caster_level < 0x08) { attack_difficulty ++; } if( caster_level < 0x06) { attack_difficulty ++; } if( caster_level < 0x05) { attack_difficulty ++; } if( caster_level < 0x04) { attack_difficulty ++; } if( caster_level < 0x03) { attack_difficulty ++; } if( magery_difficulty < attack_difficulty) { difficulty = attack_difficulty; } else { difficulty = magery_difficulty; } string mana_pen = magery_difficulty; string level_pen = attack_difficulty; string b = difficulty; return( difficulty);
}

