function void pick_and_cast_spell(obj caster) {
  obj target = getFirstVisableTargetInRange( caster, 0x09); if( target == NULL( )) { return( ); } loc there = getLocation( target); int cur_hp = getCurHP( caster); cur_mana = getCurMana( caster); int intelligence = getIntelligence( caster); if( ! hasObjVar( this, "spellCastersLevel")) { return( ); } caster_level = getObjVar( caster, "spellCastersLevel"); int alignment; if( ! getCompileFlag( 0x01)) { alignment = getNotoriety( caster); } else { alignment = getKarmaLevel( caster); } int unused; int hp_zone; int spell_idx; int roll; int targetType; int mana_cost; int offensive_thresh; int neutral; int good; int heal; if( hp_threshold_high <= cur_hp) { hp_zone = 0x01; } if( hp_threshold_low <= cur_hp) { if( cur_hp < hp_threshold_high) { hp_zone = 0x02; } } if( hp_threshold_critical <= cur_hp) { if( cur_hp < hp_threshold_low) { hp_zone = 0x03; } } else { hp_zone = 0x04; } string s_hp_high = hp_threshold_high; string s_hp_low = hp_threshold_low; string s_hp_crit = hp_threshold_critical; string s_cur_hp = cur_hp; string s_hp_zone = hp_zone; spell_idx = 0x00; switch( hp_zone) { case 0x01 offensive_thresh = 0x00; break; case 0x02 offensive_thresh = 0x37; neutral = 0x28; good = 0x1C; heal = 0x03; break; case 0x03 offensive_thresh = 0x50; neutral = 0x46; good = 0x3C; heal = 0x0F; break; case 0x04 offensive_thresh = 0x5F; neutral = 0x5A; good = 0x55; heal = 0x0F; break; case 0x05 offensive_thresh = 0x64; neutral = 0x64; good = 0x55; heal = 0x0F; break; default break; } list offensive_spells = 0x1F4A, 0x03, 0x0A, 0x1F5A, 0x02, 0x1A, 0x1F3E, 0x03, 0x06, 0x1F47, 0x03, 0x0A, 0x1F40, 0x03, 0x06, 0x1F2E, 0x03, 0x02, 0x1F30, 0x03, 0x02, 0x1F34, 0x03, 0x02; list combat_spells = 0x1F5F, 0x03, 0x34, 0x1F57, 0x03, 0x1A, 0x1F56, 0x03, 0x1A, 0x1F52, 0x03, 0x10, 0x1F4A, 0x03, 0x0A, 0x1F3E, 0x03, 0x06, 0x1F38, 0x03, 0x04, 0x1F32, 0x03, 0x02; list neutral_spells = 0x1F61, 0x03, 0x34, 0x1F50, 0x01, 0x10, 0x1F4B, 0x02, 0x0A; list good_spells = 0x1F3D, 0x01, 0x06, 0x1F3B, 0x01, 0x04, 0x1F3C, 0x01, 0x04, 0x1F36, 0x01, 0x04, 0x1F35, 0x01, 0x04; list heal_spells = 0x1F49, 0x01, 0x0A, 0x1F31, 0x01, 0x02; list power_spells = 0x1F58, 0x01, 0x1A; string s_mana = cur_mana; if( cur_mana < 0x02) { int attack_roll = random( 0x01, 0x64); if( attack_roll < 0x23) { attack( this, target); return( ); } else { return( ); } } roll = random( 0x00, 0x64); if( offensive_thresh <= roll) { if( alignment < 0x00) { spell_idx = pick_offensive_spell_level( ); if( spell_idx < 0x08) { spell_scroll_type = offensive_spells [ spell_idx * 0x03 ]; targetType = offensive_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = offensive_spells [ ( spell_idx * 0x03) + 0x02 ]; } else { spell_idx = ( spell_idx - 0x08); spell_scroll_type = combat_spells [ spell_idx * 0x03 ]; targetType = combat_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = combat_spells [ ( spell_idx * 0x03) + 0x02 ]; } } else { spell_idx = ( pick_combat_spell_level( ) - 0x08); spell_scroll_type = combat_spells [ spell_idx * 0x03 ]; targetType = combat_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = combat_spells [ ( spell_idx * 0x03) + 0x02 ]; } } if( neutral <= roll) { if( roll < offensive_thresh) { spell_idx = ( pick_neutral_spell_level( ) - 0x10); if( spell_idx == ( 0x00 - 0x10)) { pick_and_cast_spell( this); return( ); } spell_scroll_type = neutral_spells [ spell_idx * 0x03 ]; targetType = neutral_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = neutral_spells [ ( spell_idx * 0x03) + 0x02 ]; } } if( good <= roll) { if( roll < neutral) { spell_idx = ( pick_good_spell_level( ) - 0x13); if( spell_idx == ( 0x00 - 0x13)) { pick_and_cast_spell( this); return( ); } spell_scroll_type = good_spells [ spell_idx * 0x03 ]; targetType = good_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = good_spells [ ( spell_idx * 0x03) + 0x02 ]; } } if( heal <= roll) { if( roll < good) { spell_idx = ( pick_heal_spell_level( ) - 0x18); spell_scroll_type = heal_spells [ spell_idx * 0x03 ]; targetType = heal_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = heal_spells [ ( spell_idx * 0x03) + 0x02 ]; } } else { spell_idx = ( select_divine_spell( ) - 0x1A); if( spell_idx == ( 0x00 - 0x1A)) { pick_and_cast_spell( this); return( ); } spell_scroll_type = power_spells [ spell_idx * 0x03 ]; targetType = power_spells [ ( spell_idx * 0x03) + 0x01 ]; mana_cost = power_spells [ ( spell_idx * 0x03) + 0x02 ]; } obj scroll = createGlobalObjectIn( spell_scroll_type, caster); if( scroll == NULL( )) { return( ); } obj spell_target; loc unused_loc; if( spend_mana( caster, mana_cost) == 0x00) { deleteObject( scroll); list unused_list; shortcallback( this, 0x01, 0x48); return( ); } setObjVar( scroll, "user", caster); string s_target_type = targetType; switch( targetType) { case 0x01 spell_target = caster; setObjVar( scroll, "target", spell_target); break; case 0x02 spell_target = target; setObjVar( scroll, "target", spell_target); break; case 0x03 spell_target = target; setObjVar( scroll, "target", spell_target); break; default } shortcallback( scroll, 0x00, 0x49); callback( caster, 0x03, 0x48); return( );
