function int validate_cast_prereqs(obj user, int mana_cost) {
  obj rightHand = getItemAtSlot( user, 0x01); obj leftHand = getItemAtSlot( user, 0x02); if( ! is_hand_free( rightHand)) { barkToHued( user, user, 0x22, "Your hands must be free to cast spells."); return( 0x00); } if( getCompileFlag( 0x01)) { if( ! is_hand_free( leftHand)) { barkToHued( user, user, 0x22, "Your hands must be free to cast spells."); return( 0x00); } } else { if( ( ! isUsingVirtueShield( user)) && ( ! is_hand_free( leftHand))) { barkToHued( user, user, 0x22, "Your hands must be free to cast spells."); return( 0x00); } } if( ! check_mana( user, mana_cost)) { barkToHued( user, user, 0x22, "Not enough mana to cast this spell."); return( 0x00); } if( isDead( user)) { return( 0x00); } return( 0x01);
