function int attempt_spell_cast(obj user, loc usedon, int spell_index, int from_scroll) {
  if( isPlayer( user)) { if( hasObjVar( user, "spellCastersLevel")) { removeObjVar( user, "spellCastersLevel"); } } reveal_impl( user, 0x00); int circle = circle_from_index( spell_index); int mana_cost = mana_cost_for_circle( circle); if( ! check_cast_conditions( user, usedon, mana_cost)) { return( 0x00); } int circle_reduction = 0x00; if( from_scroll) { circle_reduction = 0x02; } int cast_time_ms = get_skill_threshold( circle - circle_reduction); if( testAndLearnSkill( user, 0x19, cast_time_ms, 0x28) <= 0x00) { return( 0x00); } loseMana( user, mana_cost); return( 0x01);
}

