function int consume_reagents(obj user, list reagents) {
  int reagent = 0x00; int missing = 0x00; for( int i = 0x00; ( i < numInList( reagents)) && ( missing == 0x00); i ++) { reagent = reagents [ i ]; if( getGeneric( user, reagent) <= 0x00) { missing = 0x01; break; } } if( missing == 0x01) { if( isPlayer( user)) { barkToHued( user, user, 0x22, "More reagents are needed for this spell."); } return( 0x00); } else { for( int j = 0x00; j < numInList( reagents); j ++) { reagent = reagents [ j ]; destroyGeneric( user, reagent, 0x01); } return( 0x01); } if( isPlayer( user)) { bark( user, "BUG! Please report: Invalid takeReagent return."); } return( 0x00);
}

