trigger targetobj {
  if( usedon == NULL( )) { return( 0x00); } systemMessage( user, "Targetobj called"); setObjVar( this, "ObjSelected", 0x01); loc target_loc = getLocation( usedon); int tile_height = getTileHeight( 0x1019); setZ( target_loc, getZ( target_loc) + getHeight( usedon)); int can_place = canExistAt( target_loc, tile_height, 0x01); obj wheel; if( can_place == 0x07) { wheel = requestCreateObjectAt( 0x1019, target_loc); if( wheel != NULL( )) { deleteObject( this); } else { systemMessage( user, "Can't create a spinning wheel there."); return( 0x00); } } else { systemMessage( user, "Can't create a spinning wheel there."); return( 0x00); } return( 0x01);
}

spinningwheeldeed.@targetloc.source:
