stables.respawn_self.source:
function void respawn_self() {
  obj new_npc = createGlobalNPCAtSpecificLoc( getTemplate( this), getLocation( this)); if( ! isValid( new_npc)) { return( ); } copyAllObjVars( new_npc, this); list contents; getContents( contents, this); debugMessage( "Items found:" + numInList( contents)); for( int i = numInList( contents) - 0x01; i >= 0x00; i --) { debugMessage( getName( contents [ 0x00 ]) + "(" + i + ")"); int rc; if( isMobile( contents [ 0x00 ])) { rc = putMobContainer( contents [ 0x00 ], new_npc); } else { rc = putObjContainer( contents [ 0x00 ], new_npc); } removeItem( contents, 0x00); } return( );
}

