stables.handle_stable_request.source:
function void handle_stable_request(obj this, obj speaker) {
  if( getMoney( speaker) < 0x1E) { if( amtGoldInBank( speaker) < 0x1E) { bark( this, "Thou dost not have 30 gold, not even in thy bank account."); return( ); } } list stabled_animals; getContents( stabled_animals, this); if( numInList( stabled_animals) > 0x64) { bark( this, "I am sorry, my stables are full."); return( ); } bark( this, "I charge 30 gold per pet for a real week's stable time. I will withdraw it from thy bank account. Which animal wouldst thou like to stable here?"); setObjVar( this, "petStablerAsker", speaker); targetObj( speaker, this); return( );
}

stables.claim_pets.source:
function void claim_pets(obj this, obj speaker) {
  int result; list contents; getContents( contents, this); if( numInList( contents) < 0x01) { bark( this, "But I have no animals stabled with me at the moment!"); return( ); } obj pet; list pet_list; obj current_pet; string response; for( int i = 0x00; i < numInList( contents); i ++) { current_pet = contents [ i ]; if( obj_list_var_contains( current_pet, "myBoss", speaker)) { response = response + "I have thy pet, " + getName( current_pet) + "... let me fetch it. "; result = teleport( current_pet, getLocation( speaker)); removeObjVar( current_pet, "isInStables"); detachScript( current_pet, "petzap"); if( ! result) { response = response + "I am sorry to inform thee that... well... it died. "; deleteObject( current_pet); } } } bark( this, response); return( );
}

stables.@speech(\"*\").source:
