}

stables.@targetobj.source:
trigger targetobj {
  if( usedon == NULL( )) { return( 0x00); } if( isHuman( usedon)) { bark( this, "HA HA HA! Sorry, I am not an inn."); return( 0x00); } if( hasScript( usedon, "destcrea")) { bark( this, "I can not stable summoned creatures."); return( 0x00); } if( ! hasObjVar( usedon, "myLoyalty")) { bark( this, "That's not tame to anyone!"); return( 0x00); } if( ! hasObjListVar( usedon, "myBoss")) { bark( this, "That's not tame to anyone!"); return( 0x00); } if( ! obj_list_var_contains( usedon, "myBoss", user)) { bark( this, "That's not your pet!"); return( 0x00); } if( getMoney( user) < 0x1E) { if( ! withdrawAndDestroy( user, 0x1E)) { bark( this, "But thou hast not the funds in thy bank account!"); return( 0x00); } } else { destroyGeneric( user, 0x0EED, 0x1E); } int success = putMobContainer( usedon, this); if( ! success) { bark( this, "I am sorry, but my stables are full."); return( 0x00); } attachScript( usedon, "petzap"); setObjVar( user, "lastStablemasterUsed", this); setObjVar( usedon, "isInStables", 0x01); bark( this, "Very well, thy pet is stabled. Thou mayst recover it by saying 'claim' to me. In one real world week, I shall sell it off if it is not claimed!"); return( 0x00);
}

starteq.@creation.source:
trigger creation {
  overloadWeight( this, 0x02); if( isWeapon( this)) { int weapon_type = 0x00; if( isSlashing( this)) { weapon_type = 0x01; } if( isBashing( this)) { weapon_type = 0x02; } if( isPiercing( this)) { weapon_type = 0x03; } if( isRanged( this)) { weapon_type = 0x04; } if( weapon_type > 0x00) { int template_id = 0x3C + weapon_type; int result = applyWeaponTemplate( this, template_id); } string look_text; look_text = getWeaponName( this) + " (practice weapon)"; setObjVar( this, "lookAtText", look_text); } return( 0x01);
}

statbase.apply_stat_spell.source:
function int apply_stat_spell(obj user, obj usedon, int stat_type, int is_up, int reverse) {
  int fizzled = 0x00; int delta; int duration; if( is_targetable_mobile( usedon)) { loc caster_loc = getLocation( user); loc there = getLocation( usedon); faceHere( user, getDirectionInternal( caster_loc, there)); if( hasObjVar( this, "magicItemModifier")) { int magic_item_mod = getObjVar( this, "magicItemModifier"); duration = 0x06 * magic_item_mod; delta = magic_item_mod; } else { duration = 0x06 * getSkillLevel( user, 0x19) / 0x05 + 0x01; delta = getSkillLevel( user, 0x19) / 0x0A + 0x01; } if( ! is_up) { delta = 0x00 - delta; } if( ! apply_stat_effect_if_absent( usedon, stat_type, delta, duration)) { fizzled = 0x01; fizzle_spell( user); } else { doMobAnimation( usedon, get_stat_change_anim( stat_type, is_up), 0x0A, 0x0F, 0x00, 0x00); sfx( there, get_stat_effect_sfx_id( stat_type, is_up), 0x00); } if( ! is_up) { apply_damage_clamped( user, usedon, 0x00, reverse); report_obj_aggression( user, usedon, 0x02, reverse); notify_spell_hit( user, usedon, reverse); receiveUnhealthyActionFrom( usedon, user); } } schedule_cleanup( this); return( fizzled);
}

