statfix.reset_stat_mods.source:
function int reset_stat_mods(obj m_target) {
  int mod; int real_val; int max_val; int result; int changed = 0x00; for( int i = 0x00; i < 0x03; i ++) { mod = getStatMod( m_target, i); if( mod != 0x00) { result = setStatMod( m_target, i, 0x00); changed = 0x01; } real_val = getRealStat( m_target, i); max_val = getStatAttributeMax( m_target, i); if( real_val != max_val) { result = setStatAttributeMax( m_target, i, real_val); changed = 0x01; } } return( changed);
}

statfix.fixStats.source:
function int fixStats(obj mob) {
  list equipped; loc mob_loc = getLocation( mob); int slot; obj item; int discard; int fixed; for( slot = 0x01; slot < 0x1A; slot ++) { item = getItemAtSlot( mob, slot); append( equipped, item); if( item != NULL( )) { discard = teleport( item, mob_loc); } } fixed = reset_stat_mods( mob); int count = numInList( equipped) + 0x01; for( slot = 0x01; slot < count; slot ++) { item = equipped [ slot - 0x01 ]; if( item != NULL( )) { discard = equipObj( item, mob, slot); } } setNaturalAC( mob, 0x00); return( fixed);
}

