function int is_allowed_script(string script_name) {
  if( script_name == "bounty") { return( 0x01); } if( script_name == "giftbag") { return( 0x01); } if( script_name == "statfix") { return( 0x01); } if( script_name == "amnesty3") { return( 0x01); } if( script_name == "amnesty4") { return( 0x01); } if( script_name == "guarded") { return( 0x01); } if( script_name == "counokay") { return( 0x01); } if( script_name == "info") { return( 0x01); } return( 0x00);
}

