  string name; int item_type = getObjType( item); switch( item_type) { case 0x0F95 case 0x0F96 case 0x0F97 case 0x0F98 case 0x0F99 case 0x0F9A case 0x0F9B case 0x0F9C if( plural == 0x01) { name = "bolts of cloth"; } else { name = "a bolt of cloth"; } break; case 0x175D case 0x175E case 0x175F case 0x1760 case 0x1761 case 0x1762 case 0x1763 case 0x1764 if( plural == 0x01) { name = "piles of folded cloth"; } else { name = "a pile of folded cloth"; } break; case 0x1765 case 0x1766 case 0x1767 case 0x1768 if( plural == 0x01) { name = "pieces of cloth"; } else { name = "a piece of cloth"; } break; case 0x1067 case 0x1068 case 0x1081 case 0x1082 if( plural == 0x01) { name = "pieces of leather"; } else { name = "a piece of leather"; } break; case 0x1078 case 0x1079 if( plural == 0x01) { name = "piles of hides"; } else { name = "a pile of hides"; } break; } return( name);
}

