function void say_taming_phrase(obj animal) {
  string name = getName( animal); removePrefix( name, "a "); removePrefix( name, "an "); switch( random( 0x00, 0x09)) { case 0x00 case 0x01 bark( this, "Here " + name + "."); break; case 0x02 case 0x03 bark( this, "Nice " + name + "."); break; case 0x04 case 0x05 bark( this, "Good " + name + "."); break; case 0x06 bark( this, "Will you be my friend?"); break; case 0x07 bark( this, "I've always wanted a pet like you."); break; case 0x08 bark( this, "Don't be afraid."); break; case 0x09 bark( this, "I won't hurt you."); break; } return( );
}

