telecheck.@callback(0x86).source:
trigger callback(0x86) {
  int success = 0x00; if( getLocation( this) == where) { if( canExistAt( where, check_width, check_height) == 0x07) { success = 0x01; } } list reply; if( success) { appendToList( reply, 0x01); } else { appendToList( reply, 0x00); } appendToList( reply, where); multimessage( requester, "telereply", reply); deleteObject( this); return( 0x01);
}

