timer.@message(\"activate\").source:
trigger message("activate") {
  if( hasObjVar( this, "time1")) { int time1 = getobjvar_int( this, "time1"); if( ! hasObjVar( this, "running")) { int running_state = 0x00; setObjVar( this, "running", running_state); if( hasObjVar( this, "count")) { int count = getobjvar_int( this, "count"); setObjVar( this, "tempCount", count); } callback( this, time1, 0x2F); return( 0x00); } } return( 0x00);
}

timer.@message(\"deactivate\").source:
trigger message("deactivate") {
  if( hasObjVar( this, "running")) { removeObjVar( this, "running"); } return( 0x00);
}

timer.@callback(0x2F).source:
trigger callback(0x2F) {
  int time1; list args; if( hasObjVar( this, "running")) { int phase = getobjvar_int( this, "running"); if( phase == 0x00) { processTriggerCmds( this, "a"); if( hasObjVar( this, "time2")) { int time2 = getobjvar_int( this, "time2"); phase = 0x01; setObjVar( this, "running", phase); callback( this, time2, 0x2F); } else { time1 = getobjvar_int( this, "time1"); callback( this, time1, 0x2F); } } else { processTriggerCmds( this, "d"); time1 = getobjvar_int( this, "time1"); phase = 0x00; setObjVar( this, "running", phase); callback( this, time1, 0x2F); } } if( hasObjVar( this, "tempCount")) { int tempCount = getobjvar_int( this, "tempCount"); if( tempCount > 0x01) { tempCount --; setObjVar( this, "tempCount", tempCount); } else { removeObjVar( this, "tempCount"); message( this, "deactivate", args); } } return( 0x00);
}

timer.@enterrange(0x07).source:
trigger enterrange(0x07) {
  if( isPlayer( target)) { if( ! hasObjVar( this, "noAuto") && ! hasObjVar( this, "running")) { list args; message( this, "activate", args); } } return( 0x01);
}

timer.@leaverange(0x07).source:
trigger leaverange(0x07) {
  if( ! hasObjVar( this, "noAuto") && hasObjVar( this, "running")) { if( isPlayer( target)) { list nearby_players; getPlayersInRange( nearby_players, getLocation( this), 0x06); if( numInList( nearby_players) == 0x00) { list args; message( this, "deactivate", args); } } } return( 0x01);
}

timer.@creation.source:
trigger creation {
  if( ! hasObjVar( this, "noAuto") && ! hasObjVar( this, "running")) { list nearby_players; getPlayersInRange( nearby_players, getLocation( this), 0x06); if( numInList( nearby_players) > 0x00) { list args; message( this, "activate", args); } } return( 0x00);
}

tinker.wear_tool.source:
function int wear_tool(obj user, obj tool) {
  if( hasObjVar( tool, "lifeRemaining")) { int lifeRemaining = getObjVar( tool, "lifeRemaining"); if( lifeRemaining > 0x01) { setObjVar( tool, "lifeRemaining", ( lifeRemaining - 0x01)); } else { string name = getNameByType( getObjType( this)); systemMessage( user, "You destroyed the " + name + "."); return( 0x01); } } else { setObjVar( tool, "lifeRemaining", 0x32); } return( 0x00);
}

tinker.place_item.source:
function void place_item(obj user_obj, obj item, string msg) {
  obj pack = getBackpack( user_obj); string full_msg = msg; if( isValid( pack) && canHold( pack, item)) { concat( full_msg, " in your backpack."); int result = putObjContainer( item, pack); } else { concat( full_msg, " at your feet."); } systemMessage( user_obj, full_msg); return( );
}

tinker.craft_item.source:
function void craft_item() {
  craft_ready = 0x00; obj new_item; list resource_list; int remaining; int count; int resource_result; obj backpack = getBackpack( crafter); string name; string item_pronoun = "it"; if( is_metal) { is_metal = 0x00; new_item = createNoResObjectAt( item_type, getLocation( crafter)); transferResources( new_item, material_obj, material_cost, "metal"); name = getName( new_item); switch( item_type) { case 0x1053 case 0x105D case 0x0F9E case 0x0FBC item_pronoun = "them"; break; default break; } place_item( crafter, new_item, "You create " + name + " and put " + item_pronoun); resource_result = getResource( remaining, material_obj, "metal", 0x03, 0x02); } else { new_item = createNoResObjectAt( item_type, getLocation( crafter)); transferResources( new_item, material_obj, material_cost, "wood"); name = getName( new_item); place_item( crafter, new_item, "You create " + name + " and put it"); resource_result = getResource( remaining, material_obj, "wood", 0x03, 0x02); } if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } if( remaining < 0x01) { deleteObject( material_obj); } if( wear_tool( crafter, this)) { deleteObject( this); } return( );
}

tinker.@use.source:
trigger use {
  int obj_type = getObjType( this); if( obj_type != 0x1EBC) { if( isAtHome( this)) { systemMessage( user, "You can't use that, it belongs to someone else."); return( 0x00); } } if( hasObjVar( this, "inUse")) { systemMessage( user, "Someone else is using that"); return( 0x00); } else { setObjVar( this, "inUse", 0x00); callback( this, 0x1E, 0x1B); } loc tool_loc = getLocation( this); obj new_item; int new_type; switch( obj_type) { case 0x1059 case 0x105A new_type = random( 0x00, 0x01) + 0x1057; new_item = createNoResObjectAt( new_type, getLocation( user)); place_item( user, new_item, "You assemble the parts, and put the sextant"); destroyOne( this); if( hasObjVar( this, "inUse")) { removeObjVar( this, "inUse"); } return( 0x00); break; case 0x1053 case 0x1054 systemMessage( user, "Use that on an axle to make an axle with gears."); break; case 0x105D case 0x105E systemMessage( user, "Use that on an axle with gears to make clock parts."); break; case 0x1055 case 0x1056 systemMessage( user, "Use that on an axle with gears to make sextant parts."); break; case 0x105B case 0x105C systemMessage( user, "Use that on gears to make an axle with gears."); break; case 0x104D case 0x104E systemMessage( user, "Use that on clock parts to make a clock."); break; case 0x1051 case 0x1052 systemMessage( user, "Use that on springs to make clock parts, or a hinge to make sextant parts."); break; case 0x104F case 0x1050 systemMessage( user, "Use that on a clock frame to make a clock."); break; } targetObj( user, this); return( 0x01);
}

