  if( isPlayer( target)) { list args = 0x03; multimessage( target, "foundme", args); if( sword_given) { ebark( this, "It is good to have you back sir, but I have done all I can for thee, it is now up to you to save our village."); return( 0x01); } if( needs_hammer) { ebark( this, "Hello again! Have you found a smith's hammer for me yet?  I can't make that sword without it!"); return( 0x01); } if( needs_sword) { ebark( this, "Greetings my friend, have you brought me a longsword?"); return( 0x01); } if( greeted) { ebark( this, "Greetings again, sir.  Have you had any luck on your quest?"); return( 0x01); } bark( this, "Ah, a guest in my home, greetings my friend!"); greeted = 0x01; return( 0x01); } return( 0x01);
}

tutsage.@speech(\"*\").source:
trigger speech("*") {
  if( ! isPlayer( speaker)) { return( 0x00); } list args = 0x03; list text; string word; split( text, arg); for( int i = 0x00; i < numInList( text); i ++) { word = text [ i ]; if( ( word == "dragon") || ( word == "slay")) { if( needs_hammer) { message( speaker, "hammerquest", args); ebark( this, "The dragon won't be a problem after I make you an enchanted sword, but I need a smith's hammer to do so."); return( 0x00); } if( needs_sword) { message( speaker, "swordquest", args); ebark( this, "The dragon won't be a problem after I make you an enchanted sword, but I need an ordinary longsword to do so."); return( 0x00); } if( sword_given) { ebark( this, "With the sword I gave you, you should be able to kill the dragon, perhaps in a single blow!"); return( 0x00); } ebark( this, "Ahh, a young dragonslayer are you?  Well you will need help.  Bring me a smith's hammer, and I can make you an enchanted sword to slay the beast with!"); message( speaker, "hammerquest", args); needs_hammer = 0x01; needs_sword = 0x01; quest_active = 0x01; return( 0x00); } if( word == "hammer") { ebark( this, "You should be able to get a smith's hammer from the blacksmith in town for a modest price."); return( 0x00); } if( ( word == "sword") || ( word == "longsword")) { ebark( this, "You should be able to get a longsword from the blacksmith in town for a modest price."); return( 0x00); } if( word == "quest") { ebark( this, "Well, if you got bored, you could always go slay that cursed dragon!"); return( 0x00); } if( ( word == "help") || ( word == "assistance")) { if( needs_hammer) { ebark( this, "You should be able to get a smith's hammer from the blacksmith in town for a modest price."); return( 0x00); } if( needs_sword) { ebark( this, "You should be able to get a longsword from the blacksmith in town for a modest price."); return( 0x00); } if( sword_given) { ebark( this, "The sword I gave you is all the help I can render you."); return( 0x00); } ebark( this, "What was it you needed help with?"); return( 0x00); } if( ( word == "sword") || ( word == "glass") || ( word == "enchanted") || ( word == "longsword")) { if( needs_hammer) { ebark( this, "Given a smith's hammer and an ordinary longsword, I can make an enchanted sword!"); return( 0x00); } if( needs_sword) { ebark( this, "I'll need a regular longsword to make an enchanted sword of."); return( 0x00); } if( sword_given) { ebark( this, "That sword does potent damage, but has very limited use."); return( 0x00); } ebark( this, "I can make an enchanted sword, but I'll need a smith's hammer and an ordinary longsword to do so."); return( 0x00); needs_hammer = 0x01; needs_sword = 0x01; quest_active = 0x01; return( 0x00); } } return( 0x01);
}

tutsage.@give.source:
trigger give {
  int obj_type; obj_type = getObjType( givenobj); int ok; int tmp; obj where; list args; if( ( obj_type == 0x0FB4) || ( obj_type == 0x0FB5) || ( obj_type == 0x13E3) || ( obj_type == 0x13E4)) { if( sword_given) { ebark( this, "I have already made you a glass sword, that is all I can do for you."); return( 0x01); } if( needs_hammer) { if( quest_active) { needs_hammer = 0x00; } ok = putObjContainer( givenobj, this); if( ! ok) { ok = teleport( givenobj, getLocation( this)); ebark( this, "Oops, I dropped it."); } if( needs_sword) { ebark( this, "Yes, with this I can make you an enchanted sword to slay the dragon with!  All I need now is your longsword... you do have one don't you?"); multimessage( giver, "swordquest", args); } } if( ( ! needs_hammer) && ( ! needs_sword) && quest_active) { ebark( this, "Good, now I will make your glass sword.  Remember you can only use it once, and I can not make another!"); attachScript( sword, "glasssword"); sfx( getLocation( this), 0x3E, 0x3E); systemMessage( giver, "The sage chants for a moment, and hits your longsword with the hammer shattering the steel and revealing a blade of glass!"); where = giveItem( giver, sword); message( giver, "givenglass", args); sword_given = 0x01; } return( 0x00); } if( ( ( obj_type > 0x0F5D) && ( obj_type < 0x0F62)) || ( ( obj_type > 0x13B6) && ( obj_type < 0x13BB))) { if( sword_given) { ebark( this, "I have already made you a glass sword, that is all I can do for you."); return( 0x01); } if( needs_sword) { if( quest_active) { needs_sword = 0x00; } ok = putObjContainer( givenobj, this); if( ! ok) { ok = teleport( givenobj, getLocation( this)); ebark( this, "Oops, I dropped it."); } sword = givenobj; if( needs_hammer) { ebark( this, "I can make an enchanted sword from this, but I still need a hammer."); message( giver, "hammerquest", args); } } if( ( ! needs_hammer) && ( ! needs_sword) && quest_active) { ebark( this, "Good, now I will make your glass sword.  Remember you can only use it once, and I can not make another!"); attachScript( sword, "glasssword"); sfx( getLocation( this), 0x3E, 0x3E); systemMessage( giver, "The sage chants for a moment, and hits your longsword with the hammer shattering the steel and revealing a blade of glass!"); where = giveItem( giver, sword); message( giver, "givenglass", args); sword_given = 0x01; } return( 0x00); } return( 0x01);
}

tutwisp.run_step.source:
function void run_step() {
  string msg; hint_repeat_count = 0x00; switch( state) { case 0x01 hint_msg = "Lets get out of the inn, shall we?  Walk to the door by moving your cursor so the arrow points at it, and then hold down the right mouse button."; callback( this, 0x1E, 0x0001046A); return( ); break; case 0x02 hint_msg = "Now double click on the door to open it and then walk through."; break; case 0x03 hint_msg = "Lets go find the town bulletin board and see whats going on.  Its " + getDirection( getLocation( this), board_loc) + " of here.  You might want to open your map to help navigate by pressing Alt-R."; break; case 0x04 hint_msg = "Lets read the board and see whats going on in the area.  Double click the bulletin board to read the messages on it."; break; case 0x05 hint_msg = ""; break; case 0x06 hint_msg = "That dragon sounds dangerous.  We should seek the aide of the sage in town to see if he can help us out, he is " + getDirection( getLocation( this), sage_loc) + "."; break; case 0x07 hint_msg = "There's the sage, ask him about the dragon and see if he can help."; break; case 0x08 hint_msg = "That sword is sure to help, lets find the blacksmith, they're " + getDirection( getLocation( this), blacksmith_loc) + "."; callback( this, 0x0A, 0x0001046A); return( ); break; case 0x09 hint_msg = "There's the shopkeeper, say 'shopkeeper' near him to get his attention and you'll be shown his inventory to shop from."; break; case 0x0A hint_msg = "Okay, we have the hammer for the sage, lets head " + getDirection( getLocation( this), sage_loc) + ", back to the sage's home."; break; case 0x0B hint_msg = "You need to open your inventory to give the hammer to the sage, open it by pressing Alt-I."; break; case 0x0C hint_msg = "There's the hammer in your pack, while very close to the sage click on the hammer and drag it on top of the sage to give it to him, then right click on the inventory window to close it."; break; case 0x0D hint_msg = "Sheesh, a sword too eh?  Lets go back to the blacksmith's to buy one - " + getDirection( getLocation( this), blacksmith_loc) + "."; callback( this, 0x0A, 0x0001046A); return( ); break; case 0x0E hint_msg = "Shop now just like you did before."; break; case 0x0F hint_msg = "Okay, lets head back to the sage's home and hope this is all we need."; break; case 0x10 hint_msg = "Drag your sword from your inventory to the sage to give it to him, if you have it wielded, drag it from your 'paper doll,' which you open by pressing Alt-P."; break; case 0x11 hint_msg = "Well now that we finally have our enchanted sword, lets find the ranger to learn how to track the dragon down, he's most likely at the library, " + getDirection( getLocation( this), ranger_loc) + "."; callback( this, 0x0A, 0x0001046A); return( ); break; case 0x12 hint_msg = "There is the ranger now, ask him to 'teach tracking', and see how much he wants to teach you how to track."; break; case 0x13 hint_msg = "You're as ready as you're going to be to take on the dragon, lets head out into the woods!"; callback( this, 0x0A, 0x0001046A); return( ); break; case 0x14 hint_msg = "I have a feeling the dragon is near, you'd better wield your glass sword.  First open your 'paperdoll' by pressing Alt-P now."; break; case 0x15 hint_msg = "Unwield anything you're wielding by dragging it from your paperdoll to your pack.  Now drag the sword from your inventory to the picture of you in the paperdoll and you will wield it!"; break; case 0x16 hint_msg = "Time to kill us a dragon.  Click on the skills button on your paperdoll, then the arrow next to 'actions'.  You should now see the tracking skill in the list if you scroll down with the red ribbon some, click on that, and then select 'creatures'.  A box will appear with the monsters nearby in it, click on the dragon in that box.  If there isn't a dragon, wander some more and try again."; break; case 0x17 hint_msg = "There's the dragon!  Click on the button labeled 'peace' on your paperdoll.  This will change you to war mode.  Now walk VERY close to the dragon and double click on it to begin combat!"; break; case 0x18 hint_msg = "Combat has begun!  Slay the wicked beast!!"; break; case 0x19 hint_msg = "Congratulations!!  Take the items on the dragon's body and dragging them to your inventory."; break; } bark_via_wisp( hint_msg); set_hint_text( ); callback( this, 0x78, 0x0001046B); return( );
}

