  loc spawn_loc = 0x0E56, 0x0A3A, 0x00; int teleport_result = teleport( this, spawn_loc); faceHere( this, 0x04); state = 0x01; member string hint_msg = ""; member int hint_repeat_count; member obj pack = getBackpack( this); attachScript( pack, "tutpack"); member loc sage_loc = 0x0E9B, 0x0A7A, 0x28; member loc armorer_loc = 0x0E38, 0x0A23, 0x00; member loc blacksmith_loc = 0x0E38, 0x0A23, 0x00; member loc ranger_loc = 0x0E1C, 0x09AB, 0x00; member loc waypoint_loc; member loc dragon_loc = 0x0D6D, 0x0A56, 0x27; member loc board_loc = 0x0E56, 0x0A60, ( 0x00 - 0x02); member obj sage = createGlobalNPCAt( 0x4C, sage_loc, 0x01); member obj armorer = createGlobalNPCAt( 0x35, blacksmith_loc, 0x01); member obj provisioner = armorer; member obj ranger = createGlobalNPCAt( 0x4B, ranger_loc, 0x01); member obj dragon = createGlobalNPCAt( 0x0221, dragon_loc, 0x01); member obj board = createGlobalObjectAt( 0x1E5E, board_loc); loc door_search_loc = 0x0E54, 0x0A3F, 0x00; obj door1; obj door2; list doors; getObjectsInRange( doors, door_search_loc, 0x02); if( numInList( doors) > 0x00) { door1 = doors [ 0x00 ]; } if( numInList( doors) > 0x01) { door2 = doors [ 0x01 ]; } faceHere( sage, 0x04); setMaxFatigue( sage, 0x00); setCurFatigue( sage, 0x00); setMaxFatigue( armorer, 0x00); setCurFatigue( armorer, 0x00); setMaxFatigue( ranger, 0x00); setCurFatigue( ranger, 0x00); setMaxFatigue( dragon, 0x00); setCurFatigue( dragon, 0x00); attachScript( sage, "tutsage"); attachScript( armorer, "tutarmorer"); attachScript( armorer, "tutprovisioner"); attachScript( ranger, "tutranger"); attachScript( dragon, "tutdragon"); attachScript( board, "tutboard"); if( door1 != NULL( )) { attachScript( door1, "tutdoor"); } if( door2 != NULL( )) { attachScript( door2, "tutdoor"); } create_board_post( ); return( 0x01);
}

