tutwisp.@message(\"usedme\").source:
trigger message("usedme") {
  switch( args [ 0x00 ]) { case 0x01 if( state == 0x02) { state = 0x03; run_step( ); } break; case 0x02 if( state == 0x04) { state = 0x05; run_step( ); } break; case 0x08 if( state == 0x0B) { state = 0x0C; run_step( ); } break; case 0x06 if( state == 0x12) { state = 0x13; callback( this, 0x03, 0x000182AD); run_step( ); } break; case 0x0A if( getSkillLevel( this, 0x26) > 0x46) { state = 0x16; run_step( ); } break; case 0x07 state = 0x18; break; case 0x09 hint_msg = "Well, I have helped you all I can, I hope your adventures are as pleasant as they will be exciting!"; bark_via_wisp( hint_msg); obj w = getObjVar( this, "curWisp"); stopFollowing( w); detachScript( this, "tutwisp"); return( 0x00); break; } return( 0x01);
}

tutwisp.@speech(\"*\").source:
trigger speech("*") {
  list text; string word; split( text, arg); word = text [ 0x00 ]; if( 0x00) { if( word == "face") { systemMessage( this, "Dir:" + getFacing( this)); } if( numInList( text) == 0x02) { systemMessage( this, "2 in list"); word = text [ 0x00 ]; if( word == "state") { word = text [ 0x01 ]; int new_state = strtoi( word); state = new_state; set_hint_text( ); systemMessage( this, "New State: " + state); return( 0x00); } } } for( int i = 0x00; i < numInList( text); i ++) { word = text [ i ]; if( word == "help") { set_hint_text( ); bark_via_wisp( hint_msg); return( 0x00); } } return( 0x01);
}

