  switch( args [ 0x00 ]) { case 0x01 if( state == 0x01) { state = 0x02; run_step( ); } break; case 0x02 if( state <= 0x03) { state = 0x04; run_step( ); } break; case 0x03 if( state == 0x06) { state = 0x07; run_step( ); } if( state == 0x0A) { state = 0x0B; run_step( ); } if( state == 0x0F) { state = 0x10; run_step( ); } break; case 0x04 if( state == 0x08) { state = 0x09; callback( this, 0x03, 0x00010469); run_step( ); } case 0x05 if( state == 0x0D) { state = 0x0E; callback( this, 0x03, 0x00010469); run_step( ); } break; case 0x06 if( state == 0x11) { state = 0x12; run_step( ); } break; case 0x07 if( state == 0x16) { state = 0x17; run_step( ); } if( state == 0x13) { state = 0x14; run_step( ); } break; } return( 0x01);
}

