function void giveToUser(obj user, obj item, string label) {
  obj bp = getBackpack( user); string msg = label; if( isValid( bp) && canHold( bp, item)) { concat( msg, " in your backpack."); int r = putObjContainer( item, bp); } else { concat( msg, " at your feet."); } systemMessage( user, msg); return( );
}

