function int harvestResource(obj user, obj target, string resName, int dropBodyId, string label) {
  int value; int q = getResource( value, target, resName, 0x03, 0x02); if( value <= 0x00) { return( 0x00); } obj drop = createNoResObjectAt( dropBodyId, getLocation( user)); transferResources( drop, target, value, resName); giveToUser( user, drop, label); returnResourcesToBank( target, value, resName); return( 0x01);
}

