  if( sender != get_owner( )) { return( 0x00); } if( ! isFreelyViewable( this, sender)) { return( 0x00); } if( button == 0x00) { if( hasObjVar( this, "vendedPrice")) { removeObjVar( this, "vendedPrice"); } scriptTrig( this, 0x1C, get_owner( )); return( 0x00); } int price = text; if( price < 0x00) { systemMessage( get_owner( ), "Only containers can be set to 'not for sale.'"); } if( price > 0x000F4240) { price = 0x000F4240; } string price_str = price; string original_text = text; removePrefix( text, price_str); if( original_text == text) { if( can_remove_from_sale( this)) { price = 0x00 - 0x01; } else { return( 0x00); } } removePrefix( text, " "); removePrefix( text, " "); removePrefix( text, ","); removePrefix( text, " "); removePrefix( text, " "); if( text == "") { removeObjVar( this, "description"); } else { setObjVar( this, "description", text); } if( price < 0x00) { if( hasObjVar( this, "vendedPrice")) { removeObjVar( this, "vendedPrice"); } } else { setObjVar( this, "vendedPrice", price); } scriptTrig( this, 0x1C, get_owner( )); return( 0x00);
