trigger message("purchase") {
  obj user = args [ 0x00 ]; int result; if( user == get_owner( )) { systemMessage( user, "You take the item."); result = putObjContainer( this, getBackpack( user)); cleanup( ); return( 0x00); } obj vendor = get_vendor( ); int price = get_price( ); if( price < 0x00) { systemMessage( user, "This item is not for sale."); return( 0x00); } if( price == 0x00) { systemMessage( user, "You take " + getName( this) + "."); result = putObjContainer( this, getBackpack( user)); cleanup( ); return( 0x00); } obj gold = NULL( ); if( price > 0x00) { if( price <= getMoney( user)) { gold = transferGenericToContainer( vendor, user, 0x0EED, price); systemMessage( user, "You purchase " + getName( this) + "."); } else { if( price <= amtGoldInBank( user)) { result = withdrawFromBank( user, price); gold = transferGenericToContainer( vendor, user, 0x0EED, price); systemMessage( user, "You purchase " + getName( this) + " with the gold in your bank account."); } else { systemMessage( user, "You cannot afford this item."); return( 0x00); } } } list goldOwnerList; list goldQuantityList; if( hasObjListVar( vendor, "goldOwnerList")) { getObjListVar( goldOwnerList, vendor, "goldOwnerList"); getObjListVar( goldQuantityList, vendor, "goldQuantityList"); } for( int i = 0x00; 0x01; i ++) { if( i >= numInList( goldOwnerList)) { append( goldOwnerList, get_owner( )); append( goldQuantityList, price); break; } obj owner_entry = goldOwnerList [ i ]; if( get_owner( ) == owner_entry) { int existing_qty = goldQuantityList [ i ]; setItem( goldQuantityList, existing_qty + price, i); break; } } setObjVar( vendor, "goldOwnerList", goldOwnerList); setObjVar( vendor, "goldQuantityList", goldQuantityList); result = putObjContainer( this, getBackpack( user)); cleanup( ); return( 0x00);
}

