function obj withdraw_gold(obj user, obj owner, int limit) {
  list goldOwnerList; list goldQuantityList; getObjListVar( goldOwnerList, this, "goldOwnerList"); getObjListVar( goldQuantityList, this, "goldQuantityList"); obj result = NULL( ); for( int i = 0x00; 0x01; i ++) { if( i >= numInList( goldOwnerList)) { return( result); } obj list_owner = goldOwnerList [ i ]; if( owner == list_owner) { int amount = goldQuantityList [ i ]; if( amount > limit) { setItem( goldQuantityList, amount - limit, i); amount = limit; } else { removeItem( goldOwnerList, i); removeItem( goldQuantityList, i); } obj gold = containsObjType( this, 0x0EED); if( gold != NULL( )) { int available = getQuantity( gold); if( amount > available) { debugMessage( "Tried to transfer " + amount + " gold from vendor with only " + available + " gold."); amount = available; clearList( goldOwnerList); clearList( goldQuantityList); } result = createNoResObjectIn( 0x0EED, getBackpack( user)); transferGeneric( result, gold, amount); break; } } } setObjVar( this, "goldOwnerList", goldOwnerList); setObjVar( this, "goldQuantityList", goldQuantityList); return( result);
}

