function void collect_gold(obj user) {
  int max_carry_amount = ( getCanCarry( user) - getWeight( user)) * 0x32; if( max_carry_amount <= 0x00) { barkTo( this, user, "You are overloaded already."); return( ); } obj gold = withdraw_gold( user, user, max_carry_amount); if( gold == NULL( )) { barkTo( this, user, "I am holding no gold for you."); return( ); } int quantity = getQuantity( gold); if( quantity >= max_carry_amount) { barkTo( this, user, "Here is " + quantity + " gold, all you can carry."); } else { barkTo( this, user, "Here is " + quantity + " gold, all I've collected."); } return( );
}

