  if( ! confirm_and_clear_targeting( user, this)) { return( 0x01); } if( usedon == NULL( )) { return( 0x00); } if( check_visible_range( user, usedon, 0x0C)) { if( ! check_and_consume_reagents( user, this)) { return( 0x00); } if( try_cast_spell( user, getLocation( usedon), this)) { if( hasScript( usedon, "reflctor")) { doMobAnimation( usedon, 0x37B9, 0x0A, 0x05, 0x00, 0x00); apply_weaken_spell( usedon, user, 0x01); detachScript( usedon, "reflctor"); } else { apply_weaken_spell( user, usedon, 0x00); } } else { fizzle_spell( user); } } return( 0x00);
}

weaken.@callback(0x49).source:
trigger callback(0x49) {
  obj user = getObjVar( this, "user"); obj target = getObjVar( this, "target"); if( is_reflected( user, target)) { apply_weaken_spell( target, user, 0x01); remove_reflection( target); } else { apply_weaken_spell( user, target, 0x00); } return( 0x00);
}

weakenbase.apply_weaken_spell.source:
function int apply_weaken_spell(obj user, obj usedon, int reverse) {
  int fizzled = apply_stat_spell( user, usedon, 0x00, 0x00, reverse); return( fizzled);
}

