wearstat.use_charge.source:
function int use_charge() {
  int charges = 0x00; if( hasObjVar( this, "charges")) { charges = getObjVar( this, "charges"); } if( charges <= 0x00) { removeObjVar( this, "charges"); } else { setObjVar( this, "charges", charges - 0x01); returnResourcesToBank( this, 0x03, "magic"); } return( charges);
}

wearstat.apply_stat_modifiers.source:
function void apply_stat_modifiers(obj it, int add) {
  int str_delta = str_mod; int da = dex_mod; int int_delta = int_mod; if( ! add) { str_delta = 0x00 - str_mod; da = 0x00 - dex_mod; int_delta = 0x00 - int_mod; } apply_stat_mod( it, 0x00, str_delta); apply_stat_mod( it, 0x01, da); apply_stat_mod( it, 0x02, int_delta); return( );
}

