windentr.@enterrange(0x00).source:
trigger enterrange(0x00) {
  int min_skill = ( 0x06 - 0x01) * 0x03E8 / 0x07; int skill_chance = getSkillSuccessChance( target, 0x19, min_skill, 0x28); if( skill_chance > 0x01F4) { if( ! hasObjVar( this, "dest")) { if( ! hasObjVar( target, "justTriedToTeleportToWind")) { bark( this, "Please contact a gamemaster and let them know there is a bug here."); } setObjVar( target, "justTriedToTeleportToWind", 0x01); return( 0x01); } loc destination = getObjVar( this, "dest"); if( hasObjVar( target, "justTriedToTeleportToWind")) { removeObjVar( target, "justTriedToTeleportToWind"); } int r = teleport( target, destination); if( r == 0x00) { if( ! hasObjVar( target, "justTriedToTeleportToWind")) { bark( this, "You feel a gathering of magical energy around you, but it strangely dissipates with no effect."); } setObjVar( target, "justTriedToTeleportToWind", 0x01); } } else { if( ! hasObjVar( target, "justTriedToTeleportToWind")) { bark( this, "You are not worthy of entrance to the city of Wind!"); } setObjVar( target, "justTriedToTeleportToWind", 0x01); } return( 0x00);
}

